    String threadNameSafe(){try{return Thread.currentThread().getName();}catch(Exception e){return "unknown";}}
    String readCrashLogText(){try{File f=new File(getFilesDir(),"parental-link-crash-log.txt");if(!f.exists())return "No crash log found.";byte[] data=new byte[(int)Math.min(f.length(),200000)];try(FileInputStream in=new FileInputStream(f)){int n=in.read(data);return new String(data,0,Math.max(0,n),StandardCharsets.UTF_8);}}catch(Exception e){return "Could not read crash log: "+e.getMessage();}}
    void clearCrashLog(){try{new File(getFilesDir(),"parental-link-crash-log.txt").delete();toast("Crash log cleared");}catch(Exception e){toast("Could not clear crash log");}}
