    void startDashboardConnectionLoop(boolean immediate){loadLatestSavedChild();dashboardConnectionActive=true;dashboardHeartbeatMode=false;handler.removeCallbacks(dashboardConnectionLoop);if(immediate)prototypeRefresh(true);handler.postDelayed(dashboardConnectionLoop,12000);}
