    void prototypeRefresh(boolean redraw){loadLatestSavedChild();if(childIp==null||childIp.length()==0){searchForChildOnNetwork("No saved child IP",redraw);return;}cmdWithCallback("usage","today",resp->{clearConnectionSearch();TextView dummy=tv("",1);updateUsageViews(resp,dummy,null);rememberUsageRows(resp);refreshRemoteLockState(resp);refreshQuickMessageStatusQuiet();if(redraw&&"dashboard".equals(currentScreen))showJavaDashboardPrototype();},err->{searchForChildOnNetwork("Saved IP did not answer",redraw);out(err);if(redraw&&"dashboard".equals(currentScreen))showJavaDashboardPrototype();});}
    long heartbeatDelayMs(){if(quickChatDeliveryActive())return 3000L;if(getSharedPreferences("p",0).getBoolean("childUnlockRequestPending",false))return 5000L;if(heartbeatFailCount<=2)return 60000L;if(heartbeatFailCount==3)return 5L*60000L;if(heartbeatFailCount==4)return 15L*60000L;return 30L*60000L;}
    boolean quickChatDeliveryActive(){long until=getSharedPreferences("p",0).getLong("quickChatFastPollUntil",0);return until>System.currentTimeMillis();}
    void prototypeHeartbeat(){loadLatestSavedChild();if(childIp==null||childIp.length()==0){searchForChildOnNetwork("No saved child IP",false);return;}cmdWithCallback("hello","",resp->{clearConnectionSearch();heartbeatFailCount=0;heartbeatFailStart=0;heartbeatLastLogAt=0;updateStatusFromHello(resp);refreshQuickMessageStatusQuiet();},err->{searchForChildOnNetwork("Heartbeat could not reach child",false);long now=System.currentTimeMillis();heartbeatFailCount++;if(heartbeatFailStart==0)heartbeatFailStart=now;long delay=heartbeatDelayMs();if(heartbeatFailCount<=2||now-heartbeatLastLogAt>=delay){heartbeatLastLogAt=now;java.text.SimpleDateFormat fmt=new java.text.SimpleDateFormat("HH:mm",java.util.Locale.US);addLog("Connection","Error","Heartbeat failed","Failed from "+fmt.format(new java.util.Date(heartbeatFailStart))+" to "+fmt.format(new java.util.Date(now))+": "+err);}});}
    void updateStatusFromHello(String resp){try{SharedPreferences.Editor ed=getSharedPreferences("p",0).edit();for(String line:(resp==null?"":resp).split("\\n")){if(line.startsWith("VERSION:"))ed.putString("remoteVersion",line.substring(8).trim());else if(line.startsWith("PROTOCOL:"))ed.putString("remoteProtocol",line.substring(9).trim());else if(line.startsWith("CAPABILITIES:"))ed.putString("remoteCapabilities",line.substring(13).trim());else if(line.startsWith("PERMISSIONS:"))ed.putString("remotePermissions",line.substring(12).trim());else if(line.startsWith("DND:"))ed.putString("remoteDnd",line.substring(4).trim());else if(line.startsWith("CHILD_ICON:"))ed.putString("childIcon",normalDeviceIcon(line.substring(11).trim()));else if(line.startsWith("BATTERY:")){try{ed.putInt("remoteBattery",Integer.parseInt(line.substring(8).trim()));}catch(Exception ignored){}}else if(line.startsWith("CHARGING:"))ed.putBoolean("remoteCharging",Boolean.parseBoolean(line.substring(9).trim()));else if(line.startsWith("WIFI_BARS:")){try{ed.putInt("remoteWifiBars",Integer.parseInt(line.substring(10).trim()));}catch(Exception ignored){}}else if(line.startsWith("CURRENT_APP:")){String app=line.substring(12).trim();ed.putString("lastCurrentApp",app).putString("lastCurrentPackage",currentAppPackage(app));}else if(line.startsWith("ASK_PARENT_REQUESTED:"))ed.putBoolean("childUnlockRequestPending",Boolean.parseBoolean(line.substring(21).trim()));else if(line.startsWith("ASK_PARENT_REASON:"))ed.putString("childUnlockRequestReason",line.substring(18).trim());else if(line.startsWith("ASK_PARENT_AT:")){try{ed.putLong("childUnlockRequestAt",Long.parseLong(line.substring(14).trim()));}catch(Exception ignored){}}}applyRemoteLockState(resp,ed);liveStatusThisRun=true;ed.putLong("lastStatusMs",System.currentTimeMillis()).putBoolean("pairingMismatch",false).remove("pairingMismatchMessage").apply();if("dashboard".equals(currentScreen))runOnUiThread(()->showJavaDashboardPrototype());}catch(Exception e){addLog("Connection","Error","Heartbeat parse failed",e.getMessage());}}
    void prototypeAllowRequest(){cmdWithCallback("enable_use","prototype_request",resp->{clearUnlockRequestLocal();setLocalLockState(false);setLocalTimeoutState(false);toast("Device enabled");showJavaDashboardPrototype();},err->{toast("Enable failed");out(err);});}
