    String currentAppPackage(String raw){String app=raw==null?"":raw.trim();int start=app.lastIndexOf('('),end=app.lastIndexOf(')');if(start>=0&&end>start)return app.substring(start+1,end).trim();if(app.startsWith("com.")||app.startsWith("org."))return app;return getSharedPreferences("p",0).getString("lastCurrentPackage","");}
    String currentAppCategory(String raw){String app=raw==null?"":raw.trim();int start=app.lastIndexOf('['),end=app.lastIndexOf(']');if(start>=0&&end>start)return app.substring(start+1,end).trim();return "";}
    View currentAppIcon(String pkg,String app){ImageView icon=new ImageView(this);try{if(pkg!=null&&pkg.length()>0){icon.setImageDrawable(getPackageManager().getApplicationIcon(pkg));icon.setScaleType(ImageView.ScaleType.CENTER_CROP);return icon;}}catch(Exception ignored){}if("YouTube".equalsIgnoreCase(app)||"youtube".equalsIgnoreCase(app)){icon.setImageResource(getResources().getIdentifier("mock_youtube_icon","drawable",getPackageName()));icon.setScaleType(ImageView.ScaleType.CENTER_INSIDE);return icon;}return protoIcon("ic_proto_question",Color.rgb(245,160,45),28);}


    void showParentAppLock(){currentScreen="parent_app_lock";lockBase();SharedPreferences p=getSharedPreferences("p",0);String savedMaster=parentMasterPassword();long lockUntil=p.getLong("pinLockUntil",0);long now=System.currentTimeMillis();boolean bioEnabled=p.getBoolean("parentBiometricUnlock",false)&&canUseDeviceCredential();root.addView(tv("Parental-Link",26));root.addView(tv(parentLockPurposeTitle(),18));root.addView(UiFactory.mutedText(this,"Use the parent master password. This is the same password used for child devices.",14));if(lockUntil>now){long sec=Math.max(1,(lockUntil-now+999)/1000);root.addView(tv("Too many wrong attempts. Try again in "+sec+" seconds.",16));handler.postDelayed(()->showParentAppLock(),Math.min(lockUntil-now,60000));return;}if(savedMaster.length()==0){showCreateParentMasterPassword(p);return;}if(!authPromptLaunched&&bioEnabled){authPromptLaunched=true;handler.postDelayed(()->launchDeviceCredential(),250);}TextView dots=tv("",32);dots.setGravity(Gravity.CENTER);root.addView(dots);final StringBuilder entered=new StringBuilder();GridLayout pad=new GridLayout(this);pad.setColumnCount(3);pad.setPadding(0,24,0,16);String[] labels=bioEnabled?new String[]{"1","2","3","4","5","6","7","8","9","Back","0","Bio"}:new String[]{"1","2","3","4","5","6","7","8","9","Back","0","Clear"};for(String label:labels){Button b=btn(label);pad.addView(b,new ViewGroup.LayoutParams(getResources().getDisplayMetrics().widthPixels/3-28,130));b.setOnClickListener(v->{String t=((Button)v).getText().toString();if(t.equals("Back")){if(entered.length()>0)entered.deleteCharAt(entered.length()-1);}else if(t.equals("Clear")){entered.setLength(0);}else if(t.equals("Bio")){launchDeviceCredential();}else{if(entered.length()<8)entered.append(t);}StringBuilder stars=new StringBuilder();for(int i=0;i<entered.length();i++)stars.append("* ");dots.setText(stars.toString());if(entered.length()>=4&&entered.toString().equals(savedMaster)){unlockParentApp("master password");}else if(entered.length()==8&&!entered.toString().equals(savedMaster)){registerWrongPinAttempt();}});}root.addView(pad);root.addView(tv(bioEnabled?"Biometrics are enabled. Master password remains the fallback.":"Biometric unlock can be enabled from Settings.",13));}
    String parentLockPurposeTitle(){if("add_parent".equals(pendingSecureAction))return "Authorize add parent";if("disable_parent_biometric".equals(pendingSecureAction))return "Authorize lock setting change";return "Unlock parent dashboard";}
    void lockBase(){clearUiCallbacks();root=UiFactory.attachRoot(this);root.setPadding(36,72,36,36);log=tv("",14);}
    boolean canUseDeviceCredential(){KeyguardManager km=(KeyguardManager)getSystemService(KEYGUARD_SERVICE);return Build.VERSION.SDK_INT>=21&&km!=null&&km.isDeviceSecure();}
    void launchDeviceCredential(){try{KeyguardManager km=(KeyguardManager)getSystemService(KEYGUARD_SERVICE);if(Build.VERSION.SDK_INT>=21&&km!=null&&km.isDeviceSecure()){Intent i=km.createConfirmDeviceCredentialIntent("Parental-Link",parentLockPurposeTitle());if(i!=null){credentialPromptActive=true;startActivityForResult(i,AUTH_REQUEST);}}}catch(Exception e){credentialPromptActive=false;toast("Biometric unlock unavailable");}}
    void unlockParentApp(String method){SharedPreferences.Editor e=getSharedPreferences("p",0).edit();e.putInt("pinFailCount",0).putLong("pinLockUntil",0).apply();unlockedThisRun=true;addLog("Parent app unlocked by "+method);String action=pendingSecureAction;pendingSecureAction="";if("add_parent".equals(action)){addLog("Security","Info","Add parent unlocked","Parent security unlock completed before showing second-parent QR");showAddParentScaffoldUnlocked();return;}if("unlock_request".equals(action)){showUnlockRequestScreen();return;}if("disable_parent_biometric".equals(action)){getSharedPreferences("p",0).edit().putBoolean("parentBiometricUnlock",false).putBoolean("parentLockConfigured",true).apply();addLog("Security","Info","Biometric unlock disabled","Parent lock check completed first");toast("Biometric unlock disabled");showSettingsScreen();return;}showJavaDashboardPrototype();}
    void registerWrongPinAttempt(){SharedPreferences p=getSharedPreferences("p",0);int fails=p.getInt("pinFailCount",0)+1;long[] delays={5000L,30000L,60000L,900000L,3600000L};long d=delays[Math.min(fails-1,delays.length-1)];p.edit().putInt("pinFailCount",fails).putLong("pinLockUntil",System.currentTimeMillis()+d).apply();addLog("Wrong parent master password attempt");toast("Wrong master password");showParentAppLock();}
    String parentMasterPassword(){SharedPreferences p=getSharedPreferences("p",0);String master=p.getString("masterPassword","");if(master.length()==0)master=p.getString("parentPassword","");if(master.length()==0){String oldPin=p.getString("appPin","");if(oldPin.length()>0){p.edit().putString("masterPassword",oldPin).putString("parentPassword",oldPin).putBoolean("masterPasswordSet",true).remove("appPin").apply();master=oldPin;}}return master;}
    void showCreateParentMasterPassword(SharedPreferences p){root.addView(tv("Create one 4 to 8 digit master password for this parent.",15));root.addView(UiFactory.mutedText(this,"This same password unlocks the parent app and supervises child device settings.",13));EditText p1=new EditText(this);p1.setHint("Master password");p1.setInputType(InputType.TYPE_CLASS_NUMBER|InputType.TYPE_NUMBER_VARIATION_PASSWORD);p1.setFilters(new InputFilter[]{new InputFilter.LengthFilter(8)});root.addView(p1);addNumericPad(p1,8,false);Button save=btn("Save master password and unlock");root.addView(save);save.setOnClickListener(v->{String a=p1.getText().toString().trim();if(a.length()<4||a.length()>8){toast("Use 4 to 8 digits");return;}p.edit().putString("masterPassword",a).putString("parentPassword",a).putBoolean("masterPasswordSet",true).remove("appPin").putInt("pinFailCount",0).putLong("pinLockUntil",0).apply();unlockParentApp("new master password");});}
