    LinearLayout requestCard(SharedPreferences p){
        LinearLayout card=dashboardCard();
        int count=requestCount(p);int page=Math.min(p.getInt("requestPage",0),Math.max(0,count-1));boolean pending=count>0;
        LinearLayout.LayoutParams cardLp=(LinearLayout.LayoutParams)card.getLayoutParams();cardLp.height=UiFactory.dp(this,136);card.setLayoutParams(cardLp);
        card.setBackground(UiFactory.rounded(this,pending?(UiFactory.isDark(this)?Color.rgb(45,24,30):Color.rgb(255,242,244)):UiFactory.panel(this),16));
        LinearLayout head=new LinearLayout(this);head.setOrientation(LinearLayout.HORIZONTAL);head.setGravity(Gravity.CENTER_VERTICAL);
        TextView title=tv("Requests",16);title.setTypeface(android.graphics.Typeface.DEFAULT_BOLD);title.setTextColor(pending?UiFactory.red():UiFactory.textColor(this));title.setPadding(0,0,0,0);head.addView(title,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));
        if(count>1)head.addView(statusPill(String.valueOf(count),UiFactory.red()));
        card.addView(head);
        if(pending){
            String kind=requestKindAt(p,page);
            TextView msg=UiFactory.mutedText(this,requestText(p,kind),14);msg.setGravity(Gravity.CENTER_VERTICAL|Gravity.LEFT);msg.setPadding(0,UiFactory.dp(this,2),0,UiFactory.dp(this,2));card.addView(msg,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,UiFactory.dp(this,42)));
            LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);
            if("unlock".equals(kind)){
                Button allow=UiFactory.primaryButton(this,"Allow now");Button snooze=btn("Snooze 15 min");row.addView(allow,new LinearLayout.LayoutParams(0,UiFactory.dp(this,38),1));row.addView(snooze,new LinearLayout.LayoutParams(0,UiFactory.dp(this,38),1));
                allow.setOnClickListener(v->cmdWithCallback("enable_use","parent_dashboard",resp->{clearUnlockRequestLocal();setLocalLockState(false);setLocalTimeoutState(false);toast("Device enabled");showConnectedParent(false);},err->{toast("Enable failed");out(err);}));
                snooze.setOnClickListener(v->cmdWithCallback("snooze_ask_parent","15",resp->{clearUnlockRequestLocal();toast("Snoozed");showConnectedParent(false);},err->{toast("Snooze failed");out(err);}));
            }else if("removal".equals(kind)){
                Button devices=btn("Open devices");row.addView(devices,new LinearLayout.LayoutParams(0,UiFactory.dp(this,38),1));devices.setOnClickListener(v->showDevicesScreen());
            }else{
                Button open=btn("Review");row.addView(open,new LinearLayout.LayoutParams(0,UiFactory.dp(this,38),1));open.setOnClickListener(v->showTroubleshootingScreen());
            }
            LinearLayout.LayoutParams rlp=new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,UiFactory.dp(this,40));rlp.setMargins(0,UiFactory.dp(this,6),0,0);card.addView(row,rlp);
            if(count>1)card.addView(UiFactory.mutedText(this,"Swipe left or right for other requests",11));
        }else{
            TextView empty=UiFactory.mutedText(this,"No requests",13);empty.setGravity(Gravity.CENTER_VERTICAL);empty.setPadding(0,0,0,0);card.addView(empty,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,UiFactory.dp(this,60)));
        }
        final float[] sx=new float[1];card.setOnTouchListener((view,event)->{if(requestCount(getSharedPreferences("p",0))<2)return false;switch(event.getAction()){case MotionEvent.ACTION_DOWN:sx[0]=event.getX();return true;case MotionEvent.ACTION_UP:float dx=event.getX()-sx[0];if(Math.abs(dx)>80){SharedPreferences pp=getSharedPreferences("p",0);int c=requestCount(pp);int n=pp.getInt("requestPage",0)+(dx<0?1:-1);if(n<0)n=c-1;if(n>=c)n=0;pp.edit().putInt("requestPage",n).apply();showConnectedParent(false);return true;}}return false;});
        return card;
    }
    boolean childRecentlyConnected(SharedPreferences p){long last=p.getLong("lastStatusMs",0);return liveStatusThisRun&&last>0&&(System.currentTimeMillis()-last)<2L*60L*1000L&&!p.getBoolean("connectionSearchActive",false)&&!p.getBoolean("pairingMismatch",false);}
    int requestCount(SharedPreferences p){if(!childRecentlyConnected(p))return 0;int c=0;if(p.getBoolean("childUnlockRequestPending",false))c++;if(p.getBoolean("childRemovalPending",false)||p.getBoolean("childRemovalRequested",false))c++;if(p.getBoolean("securityAttention",false)&&p.getLong("securityAttentionIgnoredUntil",0)<System.currentTimeMillis())c++;return c;}
    String requestKindAt(SharedPreferences p,int index){ArrayList<String> items=new ArrayList<>();if(!childRecentlyConnected(p))return "none";if(p.getBoolean("childUnlockRequestPending",false))items.add("unlock");if(p.getBoolean("childRemovalPending",false)||p.getBoolean("childRemovalRequested",false))items.add("removal");if(p.getBoolean("securityAttention",false)&&p.getLong("securityAttentionIgnoredUntil",0)<System.currentTimeMillis())items.add("attention");if(items.size()==0)return "none";return items.get(Math.max(0,Math.min(index,items.size()-1)));}
    String requestText(SharedPreferences p,String kind){if("unlock".equals(kind))return "Unlock requested - "+p.getString("childUnlockRequestReason","limitation");if("removal".equals(kind))return "Removal request is waiting for child authorisation.";if("attention".equals(kind))return p.getBoolean("pairingMismatch",false)?"Possible pairing mismatch. Repair pairing from troubleshooting.":"Security attention needs review.";return "No requests";}
    LinearLayout activityCard(SharedPreferences p){LinearLayout card=dashboardCard();card.setPadding(UiFactory.dp(this,12),UiFactory.dp(this,6),UiFactory.dp(this,12),UiFactory.dp(this,10));LinearLayout.LayoutParams clp=(LinearLayout.LayoutParams)card.getLayoutParams();clp.height=UiFactory.dp(this,330);clp.setMargins(0,0,0,UiFactory.dp(this,2));card.setLayoutParams(clp);LinearLayout head=new LinearLayout(this);head.setOrientation(LinearLayout.HORIZONTAL);head.setGravity(Gravity.CENTER_VERTICAL);TextView t=tv("Activity",15);t.setTypeface(android.graphics.Typeface.DEFAULT_BOLD);t.setPadding(0,0,0,0);head.addView(t,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));TextView view=tv("View all",12);view.setTextColor(UiFactory.blue());view.setGravity(Gravity.RIGHT|Gravity.CENTER_VERTICAL);view.setOnClickListener(v->showLogsScreen());head.addView(view,new LinearLayout.LayoutParams(UiFactory.dp(this,76),UiFactory.dp(this,28)));card.addView(head);ArrayList<String[]> rows=dashboardActivityRows();if(rows.size()==0)rows.add(new String[]{"No recent activity","Delivered","","--:--"});int shown=0;for(String[] row:rows){card.addView(activityRow(row[0],row[1],row.length>2?row[2]:"",row.length>3?row[3]:"--:--"));if(++shown>=8)break;}while(shown<8){Space sp=new Space(this);card.addView(sp,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,UiFactory.dp(this,30)));shown++;}return card;}
    ArrayList<String[]> dashboardActivityRows(){SharedPreferences prefs=getSharedPreferences("p",0);String childName=new DeviceProfile(this).childNickname();ArrayList<String[]> rows=new ArrayList<>();java.text.SimpleDateFormat fmt=new java.text.SimpleDateFormat("HH:mm",java.util.Locale.US);String cmd=prefs.getString("commandHistory","");java.util.HashSet<String> seen=new java.util.HashSet<>();if(cmd.trim().length()>0){for(String raw:cmd.split("\\n")){String[] c=raw.split("\\|",-1);if(c.length<4)continue;String id=c.length>1?c[1]:"";if(id.length()>0&&!seen.add(id))continue;long at=0;try{at=Long.parseLong(c[0]);}catch(Exception ignored){}String command=c[2];String status=c[3];String details=c.length>4?c[4]:"";String value=c.length>5?c[5]:"";String label="quick_chat".equals(command)?quickMessageTitle(details,value):prettyCommandName(command);rows.add(new String[]{childName+": "+cleanActivityLabel(label),status,details,at>0?fmt.format(new java.util.Date(at)):"--:--"});if(rows.size()>=8)return rows;}}String rawLogs=prefs.getString("logs","");if(rawLogs.trim().length()>0){for(String line:rawLogs.split("\\n")){if(line.trim().length()==0||line.contains("[Commands/"))continue;String status=line.contains("/Error]")?"Failed":(line.contains("/Warning]")?"Attention":"Delivered");rows.add(new String[]{childName+": "+cleanActivityLabel(AppLog.lineSummary(line)),status,"",logTime(line)});if(rows.size()>=8)break;}}return rows;}
    LinearLayout activityRow(String label,String status,String details,String time){boolean delivered="Delivered".equalsIgnoreCase(status)||"Executed".equalsIgnoreCase(status)||"Info".equalsIgnoreCase(status);LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);row.setGravity(Gravity.CENTER_VERTICAL);row.setPadding(UiFactory.dp(this,8),0,UiFactory.dp(this,8),0);if(!delivered){int bg="Failed".equalsIgnoreCase(status)||"Error".equalsIgnoreCase(status)?(UiFactory.isDark(this)?Color.rgb(58,28,33):Color.rgb(255,236,238)):(UiFactory.isDark(this)?Color.rgb(55,44,24):Color.rgb(255,247,225));row.setBackground(UiFactory.rounded(this,bg,10));}TextView text=UiFactory.mutedText(this,label,13);text.setSingleLine(true);text.setGravity(Gravity.CENTER_VERTICAL);text.setPadding(0,0,UiFactory.dp(this,6),0);row.addView(text,new LinearLayout.LayoutParams(0,UiFactory.dp(this,30),1));TextView stamp=UiFactory.mutedText(this,time,11);stamp.setGravity(Gravity.RIGHT|Gravity.CENTER_VERTICAL);stamp.setPadding(0,0,UiFactory.dp(this,6),0);row.addView(stamp,new LinearLayout.LayoutParams(UiFactory.dp(this,54),UiFactory.dp(this,30)));TextView icon=tv(statusIcon(status),13);icon.setGravity(Gravity.RIGHT|Gravity.CENTER_VERTICAL);icon.setPadding(0,0,0,0);row.addView(icon,new LinearLayout.LayoutParams(UiFactory.dp(this,26),UiFactory.dp(this,30)));LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,UiFactory.dp(this,32));lp.setMargins(0,UiFactory.dp(this,1),0,UiFactory.dp(this,1));row.setLayoutParams(lp);if(details!=null&&details.length()>0)row.setOnClickListener(v->new AlertDialog.Builder(this).setTitle(label+" - "+status).setMessage(details).setPositiveButton("OK",null).show());return row;}
    String statusIcon(String status){if("Delivered".equalsIgnoreCase(status)||"Executed".equalsIgnoreCase(status)||"Info".equalsIgnoreCase(status))return "\u2713";if("Sending".equalsIgnoreCase(status)||"Attention".equalsIgnoreCase(status))return "\u2026";if("Failed".equalsIgnoreCase(status)||"Error".equalsIgnoreCase(status))return "X";return "\u2022";}
    String cleanActivityLabel(String s){if(s==null)return "";return s.replace("\u274C","").replace("\u26A0\uFE0F","").replace("\u2705","").trim();}
    String logTime(String line){try{int sp=line.indexOf(' ');if(sp>0&&line.length()>=16)return line.substring(11,16);}catch(Exception ignored){}return "--:--";}
        void setLocalLockState(boolean disabled){getSharedPreferences("p",0).edit().putBoolean("parentChildDisabled",disabled).apply();}
    void setLocalTimeoutState(boolean active){getSharedPreferences("p",0).edit().putBoolean("parentTimeoutActive",active).apply();}
    void applyRemoteLockState(String resp,SharedPreferences.Editor ed){try{Boolean active=null;String mode="";long until=0;for(String line:(resp==null?"":resp).split("\\n")){if(line.startsWith("LOCK_ACTIVE:"))active=Boolean.parseBoolean(line.substring(12).trim());else if(line.startsWith("LOCK_MODE:"))mode=line.substring(10).trim();else if(line.startsWith("LOCK_UNTIL:")){try{until=Long.parseLong(line.substring(11).trim());}catch(Exception ignored){}}}if(active==null)return;boolean oldTimeout=getSharedPreferences("p",0).getBoolean("parentTimeoutActive",false);boolean oldDisabled=getSharedPreferences("p",0).getBoolean("parentChildDisabled",false);boolean timeout=active&&"timeout".equals(mode);boolean disabled=active&&!timeout;ed.putBoolean("parentTimeoutActive",timeout).putBoolean("parentChildDisabled",disabled).putString("childLockMode",mode).putLong("childLockUntil",until);if(oldTimeout&&!timeout)addLog("Activity","Info","Child tablet left timeout","Child reported timeout is no longer active");if(oldDisabled&&!disabled)addLog("Activity","Info","Child tablet unblocked","Child reported device block is no longer active");}catch(Exception e){addLog("Connection","Warning","Lock state parse failed",e.getMessage());}}
    void refreshRemoteLockState(String resp){SharedPreferences.Editor ed=getSharedPreferences("p",0).edit();applyRemoteLockState(resp,ed);ed.apply();}
    void rememberUsageRows(String resp){StringBuilder rows=new StringBuilder();boolean usage=false;int n=0;for(String line:(resp==null?"":resp).split("\\n")){String clean=line.trim();if(clean.equals("Usage today:")){usage=true;continue;}if(!usage||clean.length()==0)continue;if(clean.endsWith(" min")&&clean.contains(": ")){rows.append(clean).append("\n");if(++n>=20)break;}}getSharedPreferences("p",0).edit().putString("todayUsageRows",rows.toString().trim()).apply();}
    String customSlotLabel(int slot){String action=getSharedPreferences("p",0).getString("quickSlot"+slot,"");return action.length()==0?"Choose\naction":shortMenuLabel(action).replace(" ","\n");}
    String customSlotIcon(int slot){String action=getSharedPreferences("p",0).getString("quickSlot"+slot,"");String icon=menuIconDrawable(action);return icon.length()>0?icon:"ic_proto_plus";}
    void runCustomSlot(int slot){String action=getSharedPreferences("p",0).getString("quickSlot"+slot,"");if(action.length()==0)chooseQuickSlot(slot);else handleMenuAction(action);}
    String connectionLine(){SharedPreferences p=getSharedPreferences("p",0);if(p.getBoolean("pairingMismatch",false))return "Possible pairing mismatch";long last=p.getLong("lastStatusMs",0);if(last<=0)return "Connected locally - no child status yet";long age=(System.currentTimeMillis()-last)/60000;return age<2?"Online":"Last sync: "+elapsedMinutesText(age)+" ago";}
    String elapsedMinutesText(long min){if(min<1)return "just now";if(min<60)return min+" min";long h=min/60,m=min%60;return m==0?h+"h":h+"h "+m+"m";}
    String latestActivityLines(){SharedPreferences prefs=getSharedPreferences("p",0);StringBuilder sb=new StringBuilder("Activity\n");int n=0;String cmd=prefs.getString("commandHistory","");java.util.HashSet<String> seen=new java.util.HashSet<>();if(cmd.trim().length()>0){for(String row:cmd.split("\\n")){String[] c=row.split("\\|",-1);if(c.length<4)continue;String id=c.length>1?c[1]:"";if(id.length()>0&&!seen.add(id))continue;String command=c[2];String status=c[3];String details=c.length>4?c[4]:"";String value=c.length>5?c[5]:"";sb.append(compactActivityLine(command,status,details,value)).append("\n");if(++n>=3)break;}}String raw=prefs.getString("logs","");if(raw.trim().length()>0){for(String line:raw.split("\\n")){if(line.trim().length()==0)continue;if(line.contains("[Commands/"))continue;sb.append(AppLog.lineSummary(line)).append("\n");if(++n>=5)break;}}if(n==0)sb.append("No recent activity");return sb.toString().trim();}
    String compactActivityLine(String command,String status,String details,String value){if("quick_chat".equals(command)){String title=quickMessageTitle(details,value);return "Message: "+title+" - "+status;}return prettyCommandName(command)+" - "+status;}
    String quickMessageTitle(String details,String value){String d=details==null?"":details.trim();if(d.length()>0&&!d.equalsIgnoreCase("Delivered")&&!d.equalsIgnoreCase("Sending"))return d;String v=value==null?"":value;String[] parts=v.split("\\|",5);if(parts.length>=3)return (parts[1]+" "+parts[2]).trim();return "Chat";}
    String prettyCommandName(String command){if(command==null)return "Command";String c=command.trim();if(c.equals("volume"))return "Media volume";if(c.equals("disable_use"))return "Block device";if(c.equals("enable_use"))return "Enable device";if(c.equals("lock_timeout"))return "Start timeout";if(c.equals("stop_timeout"))return "Stop timeout";if(c.equals("remove_all_limitations"))return "Remove all limitations";if(c.equals("quick_chat"))return "Chat";if(c.equals("ping"))return "Ring device";return c.replace('_',' ');}
