    void showVolumeScreen(){base("Volume");currentScreen="media_volume";root.addView(volumeSectionLabel("Maximum limits",UiFactory.red()));volumeControlRow("Media","media","limit",UiFactory.red());volumeControlRow("Calls","calls","limit",UiFactory.red());volumeControlRow("Notifications","notifications","limit",UiFactory.red());LinearLayout.LayoutParams dlp=new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,UiFactory.dp(this,1));dlp.setMargins(0,UiFactory.dp(this,12),0,UiFactory.dp(this,8));View divider=menuDivider();root.addView(divider,dlp);root.addView(volumeSectionLabel("Current volume",UiFactory.green()));volumeControlRow("Media","media","current",UiFactory.green());volumeControlRow("Calls","calls","current",UiFactory.green());volumeControlRow("Notifications","notifications","current",UiFactory.green());Button mute=iconTextButton(getSharedPreferences("p",0).getBoolean("parentMediaMuted",false)?"ic_proto_volume":"ic_proto_mute",getSharedPreferences("p",0).getBoolean("parentMediaMuted",false)?"Unmute media":"Mute media");root.addView(mute,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,UiFactory.dp(this,46)));mute.setOnClickListener(v->toggleMediaMuteFromVolume());root.addView(log);}
