    void volumeControlRow(String label,String stream,String mode,int color){SharedPreferences p=getSharedPreferences("p",0);String key="volume_"+mode+"_"+stream;String limitKey="volume_limit_"+stream;String currentKey="volume_current_"+stream;final int[] percent={p.getInt(key,p.getInt("parentVolume",50))};if("current".equals(mode))percent[0]=Math.min(percent[0],p.getInt(limitKey,100));LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);row.setGravity(Gravity.CENTER_VERTICAL);row.setPadding(0,UiFactory.dp(this,2),0,UiFactory.dp(this,2));LinearLayout labelBox=new LinearLayout(this);labelBox.setOrientation(LinearLayout.VERTICAL);labelBox.setGravity(Gravity.CENTER_VERTICAL);TextView name=tv(label,12);name.setSingleLine(false);name.setMaxLines(2);name.setTextColor(color);name.setPadding(0,0,0,0);TextView value=tv(percent[0]+"%",12);value.setTextColor(color);value.setPadding(0,0,0,0);labelBox.addView(name);labelBox.addView(value);Button down=btn("-");Button up=btn("+");compactStepButton(down);compactStepButton(up);SeekBar bar=new SeekBar(this);bar.setMax("current".equals(mode)?Math.max(0,p.getInt(limitKey,100)):100);bar.setProgress(percent[0]);row.addView(labelBox,new LinearLayout.LayoutParams(UiFactory.dp(this,96),UiFactory.dp(this,50)));row.addView(down,new LinearLayout.LayoutParams(UiFactory.dp(this,38),UiFactory.dp(this,42)));row.addView(bar,new LinearLayout.LayoutParams(0,UiFactory.dp(this,42),1));row.addView(up,new LinearLayout.LayoutParams(UiFactory.dp(this,38),UiFactory.dp(this,42)));root.addView(row);Runnable send=()->{int maxAllowed="current".equals(mode)?p.getInt(limitKey,100):100;percent[0]=Math.max(0,Math.min(maxAllowed,percent[0]));SharedPreferences.Editor edit=p.edit().putInt(key,percent[0]).putInt("parentVolume",percent[0]);if("limit".equals(mode))edit.putInt(currentKey,Math.min(p.getInt(currentKey,percent[0]),percent[0]));edit.apply();value.setText(percent[0]+"%");bar.setMax("current".equals(mode)?Math.max(0,p.getInt(limitKey,100)):100);bar.setProgress(percent[0]);cmd("volume",stream+"|"+percent[0]+"|"+("current".equals(mode)?"current":"set"));};down.setOnClickListener(v->{percent[0]-=5;send.run();});up.setOnClickListener(v->{percent[0]+=5;send.run();});bar.setOnSeekBarChangeListener(new SeekBar.OnSeekBarChangeListener(){public void onProgressChanged(SeekBar s,int progress,boolean fromUser){int max="current".equals(mode)?p.getInt(limitKey,100):100;percent[0]=Math.max(0,Math.min(max,progress));value.setText(percent[0]+"%");}public void onStartTrackingTouch(SeekBar s){}public void onStopTrackingTouch(SeekBar s){send.run();}});}
