    void toggleMediaMuteFromVolume(){SharedPreferences p=getSharedPreferences("p",0);boolean muted=p.getBoolean("parentMediaMuted",false);if(muted)cmdWithCallback("volume","media|"+p.getInt("volume_current_media",50)+"|unmute",resp->{p.edit().putBoolean("parentMediaMuted",false).apply();toast("Unmuted");showVolumeScreen();},err->{toast("Unmute failed");out(err);});else cmdWithCallback("volume","media|0|mute",resp->{p.edit().putBoolean("parentMediaMuted",true).apply();toast("Muted");showVolumeScreen();},err->{toast("Mute failed");out(err);});}

