    void showTimeoutPicker(boolean prototype){final int[] minutes={Math.max(1,getSharedPreferences("p",0).getInt("lastTimeoutMinutes",5))};LinearLayout box=new LinearLayout(this);box.setOrientation(LinearLayout.VERTICAL);box.setPadding(UiFactory.dp(this,8),UiFactory.dp(this,8),UiFactory.dp(this,8),0);TextView value=tv("",34);value.setTypeface(android.graphics.Typeface.DEFAULT_BOLD);value.setGravity(Gravity.CENTER);EditText input=oneLine("Minutes");input.setInputType(InputType.TYPE_CLASS_NUMBER);input.setGravity(Gravity.CENTER);input.setText(String.valueOf(minutes[0]));LinearLayout quick=new LinearLayout(this);quick.setOrientation(LinearLayout.HORIZONTAL);Button minus10=btn("-10");Button minus5=btn("-5");Button plus5=btn("+5");Button plus10=btn("+10");quick.addView(minus10,new LinearLayout.LayoutParams(0,UiFactory.dp(this,46),1));quick.addView(minus5,new LinearLayout.LayoutParams(0,UiFactory.dp(this,46),1));quick.addView(plus5,new LinearLayout.LayoutParams(0,UiFactory.dp(this,46),1));quick.addView(plus10,new LinearLayout.LayoutParams(0,UiFactory.dp(this,46),1));box.addView(value,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,UiFactory.dp(this,58)));box.addView(input,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,UiFactory.dp(this,54)));box.addView(quick);Runnable refresh=()->{if(minutes[0]<1)minutes[0]=1;if(minutes[0]>240)minutes[0]=240;value.setText(minutes[0]+" min");if(!input.getText().toString().equals(String.valueOf(minutes[0])))input.setText(String.valueOf(minutes[0]));};View.OnClickListener adjust=v->{String raw=input.getText().toString().trim();try{if(raw.length()>0)minutes[0]=Integer.parseInt(raw);}catch(Exception ignored){}if(v==minus10)minutes[0]-=10;else if(v==minus5)minutes[0]-=5;else if(v==plus5)minutes[0]+=5;else if(v==plus10)minutes[0]+=10;refresh.run();};minus10.setOnClickListener(adjust);minus5.setOnClickListener(adjust);plus5.setOnClickListener(adjust);plus10.setOnClickListener(adjust);refresh.run();new AlertDialog.Builder(this).setTitle("Start timeout").setMessage("Choose how long the child device should stay in timeout.").setView(box).setNegativeButton("Cancel",null).setPositiveButton("Start",(d,w)->{String raw=input.getText().toString().trim();try{if(raw.length()>0)minutes[0]=Integer.parseInt(raw);}catch(Exception ignored){}minutes[0]=Math.max(1,Math.min(240,minutes[0]));getSharedPreferences("p",0).edit().putInt("lastTimeoutMinutes",minutes[0]).apply();String m=String.valueOf(minutes[0]);cmdWithCallback("lock_timeout",m,resp->{setLocalTimeoutState(true);out(resp);if(prototype)showJavaDashboardPrototype();else showConnectedParent(false);},err->{out(err);});}).show();}

    void showParentConnection(String prefill){showParentConnection(prefill,"");}
    void showParentConnection(String prefill,String ipPrefill){base("Pair child device");currentScreen="pair_parent";SharedPreferences prefs=getSharedPreferences("p",0);SharedPreferences.Editor searchEdit=prefs.edit();if(prefs.getLong("pairSearchStartedAt",0)<=0)searchEdit.putLong("pairSearchStartedAt",System.currentTimeMillis());long lastLog=prefs.getLong("pairSearchLastLogAt",0);if(System.currentTimeMillis()-lastLog>30000L){searchEdit.putLong("pairSearchLastLogAt",System.currentTimeMillis());addLog("Connection","Info","Pairing search started","Looking for child broadcasts");}searchEdit.apply();startDiscoveryListener();requestChildDiscovery();root.addView(tv("Looking for child devices on this Wi-Fi. Select a found child, then enter the visible pairing code.",15));EditText ip=oneLine("Child IP address");String savedIp=childIp.length()>0?childIp:prefs.getString("childIp","");ip.setText(ipPrefill!=null&&ipPrefill.length()>0?ipPrefill:savedIp);EditText code=oneLine("Pairing code");code.setInputType(InputType.TYPE_CLASS_NUMBER);if(prefill!=null&&prefill.length()>0)code.setText(prefill.replaceAll("\\D",""));root.addView(foundPairingDevicesView(ip,code));root.addView(ip);root.addView(code);Button pair=btn("Pair selected child");Button scan=btn("Scan QR");root.addView(pair);root.addView(scan);pair.setOnClickListener(v->pairWithChild(ip.getText().toString().trim(),code.getText().toString().trim()));scan.setOnClickListener(v->startQrScanSafely());log.setMaxLines(5);root.addView(log);}
    LinearLayout foundPairingDevicesView(EditText ipField,EditText codeField){LinearLayout box=new LinearLayout(this);box.setOrientation(LinearLayout.VERTICAL);String found=getSharedPreferences("p",0).getString("pairBroadcasts","").trim();TextView title=tv("Found devices",15);title.setTypeface(android.graphics.Typeface.DEFAULT_BOLD);box.addView(title);box.addView(UiFactory.mutedText(this,pairSearchStatusText(),12));if(found.length()==0){box.addView(UiFactory.mutedText(this,"No child broadcasts received yet.",13));schedulePairSearchRedraw(ipField,codeField);return box;}LinearLayout list=new LinearLayout(this);list.setOrientation(LinearLayout.VERTICAL);list.setBackground(UiFactory.actionShape(this,UiFactory.panel(this),10,UiFactory.border(this)));for(String row:found.split("\\n")){String clean=row.trim();if(clean.length()==0)continue;String[] parts=clean.split("\\|",-1);String ip=parts.length>0?parts[0].trim():"";String name=parts.length>1&&parts[1].trim().length()>0?parts[1].trim():"Child device";String version=parts.length>2&&parts[2].trim().length()>0?parts[2].trim():"";if(ip.length()==0)continue;LinearLayout item=new LinearLayout(this);item.setOrientation(LinearLayout.VERTICAL);item.setPadding(UiFactory.dp(this,12),UiFactory.dp(this,10),UiFactory.dp(this,12),UiFactory.dp(this,10));TextView nameView=tv(name,15);nameView.setTypeface(android.graphics.Typeface.DEFAULT_BOLD);TextView meta=UiFactory.mutedText(this,ip+(version.length()>0?" - "+version:""),12);item.addView(nameView);item.addView(meta);item.setOnClickListener(v->{ipField.setText(ip);childIp=ip;toast("Selected "+name);});list.addView(item,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,ViewGroup.LayoutParams.WRAP_CONTENT));list.addView(menuDivider());}box.addView(list);schedulePairSearchRedraw(ipField,codeField);return box;}
    String pairSearchStatusText(){long started=getSharedPreferences("p",0).getLong("pairSearchStartedAt",0);if(started<=0)return "Status: starting search";long elapsed=System.currentTimeMillis()-started;int pct=Math.min(99,(int)Math.max(1,elapsed*100L/30000L));String found=getSharedPreferences("p",0).getString("pairBroadcasts","").trim();return found.length()>0?"Status: child broadcasts found":"Status: searching "+pct+"%";}
    void schedulePairSearchRedraw(EditText ipField,EditText codeField){handler.postDelayed(()->{if(!"pair_parent".equals(currentScreen))return;if(ipField.hasFocus()||codeField.hasFocus())return;showParentConnection(codeField.getText().toString(),ipField.getText().toString());},2500);}
    void handlePairQr(String data){try{String raw=data==null?"":data.trim();Uri u=Uri.parse(raw);if("family-link".equals(u.getScheme())&&"add-parent".equals(u.getHost())){handleAddParentInvite(u);return;}String code=raw;String ip="";String q=u.getQueryParameter("code");String qi=u.getQueryParameter("ip");if(q!=null)code=q;if(qi!=null)ip=qi.trim();if(ip.length()==0){String host=u.getHost();if(host!=null&&isLikelyIp(host))ip=host;}code=code==null?"":code.replaceAll("\\D","");if(code.length()==0){toast("QR code did not contain a pairing code");if("repair_pairing".equals(currentScreen))showRepairPairingScreen();else showParentConnection("");return;}if(isLikelyIp(ip)){childIp=ip;new SavedConnection(this).saveChildIp(ip);toast("QR scanned. Connecting to "+ip);if("repair_pairing".equals(currentScreen))clearChildStatusOnly();pairWithChild(ip,code);return;}toast("QR scanned. IP missing; enter child IP manually.");if("repair_pairing".equals(currentScreen))showRepairPairingScreen(code,"");else showParentConnection(code,"");}catch(Exception e){toast("Could not read QR code");if("repair_pairing".equals(currentScreen))showRepairPairingScreen();else showParentConnection("");}}
    boolean isLikelyIp(String ip){if(ip==null)return false;String v=ip.trim();if(v.length()<7||v.length()>45)return false;if(v.equals("0.0.0.0"))return false;if(v.contains("."))return v.matches("[0-9]{1,3}(\\.[0-9]{1,3}){3}");return v.contains(":");}
    void pairWithChild(String ip,String code){if(ip==null)ip="";if(code==null)code="";ip=ip.trim();code=code.replaceAll("\\D","");if(ip.length()==0||code.length()==0){toast("Enter child IP and pairing code");return;}final String targetIp=ip;final String targetCode=code;out("Pairing with "+targetIp+" ...");new Thread(()->{try{Socket s=new Socket();s.connect(new InetSocketAddress(targetIp,PORT),3500);PrintWriter w=new PrintWriter(s.getOutputStream(),true);BufferedReader r=new BufferedReader(new InputStreamReader(s.getInputStream()));w.println("PAIR|"+targetCode+"|"+getSharedPreferences("p",0).getString("localDeviceId",""));String resp=r.readLine();s.close();if(resp!=null&&resp.startsWith("OK|")){String[] parts=resp.split("\\|");String k=parts.length>1?parts[1]:"";runOnUiThread(()->handlePairingSuccess(targetIp,k,resp));}else runOnUiThread(()->out(resp==null?"No pairing response from child":resp));}catch(Exception e){runOnUiThread(()->out("Could not reach "+targetIp+". Check both devices are on the same Wi-Fi, or use Scan QR if the child shows a different IP."));}},"Parental-LinkPair").start();}
    void handlePairingSuccess(String ip,String k,String resp){try{new SavedConnection(this).saveParentConnection(ip,k);childIp=ip;try{key=Base64.getDecoder().decode(k);}catch(Exception ignored){}unlockedThisRun=true;savePairingResponse(ip,resp);getSharedPreferences("p",0).edit().putBoolean("pairingMismatch",false).remove("pairingMismatchReason").putLong("lastStatusMs",System.currentTimeMillis()).apply();showMasterPasswordAfterPairing(ip,resp);}catch(Exception e){toast("Pairing saved with errors");out(e.getMessage());}}
    void savePairingResponse(String ip,String resp){try{String[] p=(resp==null?"":resp).split("\\|");SharedPreferences.Editor e=getSharedPreferences("p",0).edit();e.putString("childIp",ip);if(p.length>3)e.putString("remoteVersion",p[3]);if(p.length>4)e.putString("remoteProtocol",p[4]);if(p.length>6)e.putString("remoteCapabilities",p[6]);if(p.length>7&&p[7].trim().length()>0)e.putString("childDeviceModel",p[7].trim());String internal=(p.length>2&&p[2].length()>0?p[2]:"child-"+UUID.randomUUID().toString());e.putString("childInternalId",internal).putString("childIdentityKey",internal+"@"+ip).apply();}catch(Exception ignored){}}
    void showMasterPasswordAfterPairing(String ip,String resp){base("Child connected");currentScreen="pair_master_password";SharedPreferences p=getSharedPreferences("p",0);root.addView(tv("Connected to child device",20));root.addView(UiFactory.mutedText(this,"Name this device and set the parent master password. Keep one password for this parent; it applies to all child devices.",14));EditText nick=oneLine("Child name");String model=p.getString("childDeviceModel","").trim();nick.setText(p.getString("childNickname",model.length()>0?model:"Child tablet"));root.addView(nick);final String[] selectedIcon={deviceIconEmoji(p.getString("childIcon","\uD83D\uDCFA"))};TextView iconButton=tv(selectedIcon[0],32);iconButton.setGravity(Gravity.CENTER);iconButton.setBackground(UiFactory.actionShape(this,UiFactory.panel(this),12,UiFactory.border(this)));root.addView(iconButton,new LinearLayout.LayoutParams(UiFactory.dp(this,64),UiFactory.dp(this,58)));iconButton.setOnClickListener(v->chooseDeviceIcon(selectedIcon[0],icon->{selectedIcon[0]=icon;iconButton.setText(icon);}));EditText pass=oneLine("Master password (4-8 digits)");pass.setInputType(InputType.TYPE_CLASS_NUMBER);pass.setFilters(new InputFilter[]{new InputFilter.LengthFilter(8)});pass.setText(parentMasterPassword());root.addView(pass);addNumericPad(pass,8,true);root.addView(UiFactory.mutedText(this,"Child address: "+ip+"\nEncrypted pairing is active.",14));Button save=btn("Done - app lock");root.addView(save);save.setOnClickListener(v->{String pw=pass.getText().toString().trim();if(pw.length()<4||pw.length()>8){toast("Use 4 to 8 digits for the master password");return;}String name=nick.getText().toString().trim();if(name.length()==0)name=model.length()>0?model:"Child tablet";String iconName=selectedIcon[0];p.edit().putString("childNickname",name).putString("childIcon",iconName).putString("parentPassword",pw).putString("masterPassword",pw).putBoolean("masterPasswordSet",true).remove("appPin").apply();cmdWithCallback("set_child_icon",iconName,iconOk->{},iconErr->{});cmdWithCallback("set_parent_password",p.getString("parentName","Parent Control")+"|"+pw,ok->{toast("Child setup saved");showParentLockSetupAfterPairing();},err->{toast("Saved locally. Child update failed.");showParentLockSetupAfterPairing();});});root.addView(log);}
    void showParentLockSetupAfterPairing(){base("Parent app lock");currentScreen="parent_lock_setup";SharedPreferences p=getSharedPreferences("p",0);root.addView(tv("Use one master password",20));root.addView(UiFactory.mutedText(this,"The parent master password unlocks this parent app and supervises child device settings. Biometrics can be enabled as a convenience, but the master password stays the fallback.",14));CheckBox bio=new CheckBox(this);bio.setText(canUseDeviceCredential()?"Unlock with biometrics/device credential":"Biometrics unavailable until this phone has a secure screen lock");bio.setTextColor(UiFactory.textColor(this));bio.setTextSize(15);bio.setChecked(canUseDeviceCredential()&&p.getBoolean("parentBiometricUnlock",false));bio.setEnabled(canUseDeviceCredential());root.addView(bio);Button done=btn("Open dashboard");root.addView(done);done.setOnClickListener(v->{p.edit().putBoolean("parentBiometricUnlock",bio.isChecked()).putBoolean("parentLockConfigured",true).apply();unlockedThisRun=true;showJavaDashboardPrototype();});}
    String pairingSummary(String ip){SharedPreferences p=getSharedPreferences("p",0);return "Connection\nIP: "+ip+"\nVersion: "+p.getString("remoteVersion","unknown")+"\nProtocol: "+p.getString("remoteProtocol","unknown")+"\nAbilities: "+p.getString("remoteCapabilities","basic commands, usage, requests");}
