    void showChildAskParentScreen(){base("Ask Parent");currentScreen="child_requests";root.addView(tv("Send a request to your parent",16));Button unlock=btn("Ask to unlock device\nRequest access now");Button minutes=btn("Ask for 5 more minutes\nRequest more time");Button free=btn("Ask for free use\nRequest free use today");Button back=btn("Back");root.addView(unlock);root.addView(minutes);root.addView(free);root.addView(back);unlock.setOnClickListener(v->sendChildRequestToParent("unlock device"));minutes.setOnClickListener(v->sendChildRequestToParent("5 more minutes"));free.setOnClickListener(v->sendChildRequestToParent("free use"));back.setOnClickListener(v->showChild());}
    void sendChildRequestToParent(String reason){try{Intent i=new Intent(this,ChildServerService.class);i.setAction("ASK_PARENT_UNLOCK");i.putExtra("reason",reason);if(Build.VERSION.SDK_INT>=26)startForegroundService(i);else startService(i);toast("Request sent. Keep this device on the same Wi-Fi.");}catch(Exception e){toast("Request failed");addLog("Child request failed: "+e.getMessage());}showChild();}
    
    void reinitialiseChildPairing(){try{SharedPreferences.Editor e=getSharedPreferences("p",0).edit();e.remove("key");e.remove("pairCodeEpochMs");e.remove("parentKey");e.remove("parentIp");e.remove("parentName");e.remove("parentDeviceId");e.remove("childConnected");e.remove("childLinked");e.remove("pairingMismatch");e.remove("pairingMismatchReason");e.putString("role","child");e.apply();key=null;childPairingDetailsVisible=true;startChildService();toast("New pairing code created");addLog("Child pairing reinitialised from QR screen");showChild();}catch(Exception ex){toast("Could not reinitialise pairing");}}
