    void showChildRemovalAuthorisationScreen(){base("Removal requested");currentScreen="child_removal_authorisation";SharedPreferences p=getSharedPreferences("p",0);root.addView(tv("A parent requested to remove this device from Parental-Link monitoring.",17));root.addView(tv("Authorise this only if you intend to stop monitoring on this child device.",14));String reason=p.getString("childRemovalReason","parent request");root.addView(tv("Request: "+reason,13));EditText pass=oneLine("Master password / parent password");pass.setInputType(InputType.TYPE_CLASS_TEXT|InputType.TYPE_TEXT_VARIATION_PASSWORD);Button approve=btn("Authorise removal");Button deny=btn("Keep monitoring");root.addView(pass);root.addView(approve);root.addView(deny);approve.setOnClickListener(removalClick->{String saved=getSharedPreferences("p",0).getString("masterPassword",getSharedPreferences("p",0).getString("parentPassword",""));String entered=pass.getText().toString();if(saved.length()>0&&!saved.equals(entered)){toast("Wrong password");return;}authoriseChildRemovalNow();});deny.setOnClickListener(removalDenyClick->{getSharedPreferences("p",0).edit().putBoolean("childRemovalPending",false).putString("childRemovalReason","").apply();toast("Monitoring kept");showChild();});}
    void authoriseChildRemovalNow(){try{String id=getSharedPreferences("p",0).getString("localDeviceId",java.util.UUID.randomUUID().toString());getSharedPreferences("rules",0).edit().clear().apply();getSharedPreferences("p",0).edit().clear().putString("localDeviceId",id).putString("role","child").apply();toast("Parental-Link monitoring removed");addLog("Child authorised parental link removal");showChild();}catch(Exception ex){toast("Could not remove monitoring");}}

    void showChild(){base("");currentScreen="child";listenChildDashboardEvents();if(getSharedPreferences("p",0).getBoolean("childRemovalPending",false)){showChildRemovalAuthorisationScreen();return;}SharedPreferences childPrefs=getSharedPreferences("p",0);SharedPreferences.Editor childEdit=childPrefs.edit().putString("role","child");if(!childPrefs.getBoolean("childThemeDefaultSet",false))childEdit.putString("themeMode","light").putBoolean("childThemeDefaultSet",true);childEdit.apply();startChildService();ensureChildKeepAliveAccess();SharedPreferences p=getSharedPreferences("p",0);boolean connected=p.getBoolean("childConnected",false)||p.getBoolean("childLinked",false)||p.getBoolean("childRemovalPending",false);ChildHomeScreen.PairViews pv=ChildHomeScreen.render(this,root,connected,childPairingDetailsVisible,p.getString("parentName","Parent Control"),childLocalPermissionsOk(),v->startChildService(),v->showChildSettingsGate(),v->{childPairingDetailsVisible=!childPairingDetailsVisible;showChild();},v->startActivity(new Intent(this,com.enigma.familylinklite.audio.ChildAudioMessageActivity.class)),v->startActivity(new Intent(this,com.enigma.familylinklite.chat.ChildChatActivity.class)),p.getString("lastParentChat","").length()>0,v->showChildAskParentScreen(),v->showLanguageScreen(false),v->showTroubleshootingScreen(),v->showUserMenu(),deviceIconEmoji(p.getString("childIcon","\uD83D\uDCFA")),v->showChildIconPicker());childPairCodeView=pv.code;childCountdownView=pv.countdown;childQrView=pv.qr;childPairExpiryView=pv.expiry;addChildPublicOptions();updateChildPairingViews();if(!connected){LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);Button reinitPairingButton=btn("Reinitialise pairing");Button modeButton=btn("Change mode");row.addView(reinitPairingButton,new LinearLayout.LayoutParams(0,UiFactory.dp(this,48),1));row.addView(modeButton,new LinearLayout.LayoutParams(0,UiFactory.dp(this,48),1));root.addView(row);reinitPairingButton.setOnClickListener(reinitClick->reinitialiseChildPairing());modeButton.setOnClickListener(v->changePairingMode());}}
    void listenChildDashboardEvents(){try{if(br!=null)unregisterReceiver(br);}catch(Exception ignored){}br=new BroadcastReceiver(){public void onReceive(Context c,Intent i){if("com.enigma.familylinklite.CHILD_PAIRED".equals(i.getAction())){childPairingDetailsVisible=false;showChild();}else out(i.getStringExtra("msg"));}};IntentFilter filter=new IntentFilter("com.enigma.familylinklite.LOG");filter.addAction("com.enigma.familylinklite.CHILD_PAIRED");if(Build.VERSION.SDK_INT>=33)registerReceiver(br,filter,RECEIVER_NOT_EXPORTED);else registerReceiver(br,filter);}
    void ensureChildKeepAliveAccess(){try{if(Build.VERSION.SDK_INT>=33&&!hasNotificationPermission())requestPermissions(new String[]{Manifest.permission.POST_NOTIFICATIONS},7);SharedPreferences p=getSharedPreferences("p",0);if(Build.VERSION.SDK_INT>=23&&!isBatteryUnrestricted()&&!p.getBoolean("childBatteryPrompted",false)){p.edit().putBoolean("childBatteryPrompted",true).apply();handler.postDelayed(()->{toast("Allow unrestricted battery so parent commands keep working.");openBatteryPermissionSettings();},650);}}catch(Exception ignored){}}
