    void updateChildPairingViews(){try{byte[] k=getOrCreateKey();String code=currentPairCode(k);long epoch=pairCodeEpochMs();long elapsed=Math.max(0,System.currentTimeMillis()-epoch)%CryptoUtils.PAIR_CODE_WINDOW_MS;int remaining=(int)Math.max(1,(CryptoUtils.PAIR_CODE_WINDOW_MS-elapsed)/1000L);if(childPairCodeView!=null)childPairCodeView.setText(code);if(childCountdownView!=null)childCountdownView.setText("IP: "+getIp()+" - expires in "+remaining+"s");if(childPairExpiryView!=null){childPairExpiryView.setProgress(remaining);if(Build.VERSION.SDK_INT>=21){int c=remaining>150?UiFactory.green():(remaining>60?Color.rgb(245,180,40):UiFactory.red());childPairExpiryView.setProgressTintList(android.content.res.ColorStateList.valueOf(c));}}if(childQrView!=null){String ip=getIp();String payload="family-link://pair?code="+code+"&ip="+ip;childQrView.setImageBitmap(qrBitmap(payload,240));}if("child".equals(currentScreen)&&childPairCodeView!=null)handler.postDelayed(()->updateChildPairingViews(),1000);}catch(Exception ignored){}}
    void startChildService(){try{getOrCreateKey();Intent i=new Intent(this,ChildServerService.class);if(Build.VERSION.SDK_INT>=26)startForegroundService(i);else startService(i);toast("Child server running");}catch(Exception e){toast("Server start failed");out(e.getMessage());}}
