    void showAddBlockedAppDialog(LinearLayout list){SharedPreferences p=getSharedPreferences("p",0);String cached=p.getString("cachedInstalledApps","");long age=System.currentTimeMillis()-p.getLong("cachedInstalledAppsAt",0);if(cached.trim().length()>0&&age<5L*60L*1000L){showBlockedAppChooser(list,cached);return;}cmdWithCallback("list_apps","",resp->{if(resp.startsWith("Error")){toast(resp);return;}getSharedPreferences("p",0).edit().putString("cachedInstalledApps",resp).putLong("cachedInstalledAppsAt",System.currentTimeMillis()).apply();showBlockedAppChooser(list,resp);},err->{toast("Could not list apps: "+err);});}
    void showBlockedAppChooser(LinearLayout list,String resp){ArrayList<BlockedAppEntry> apps=filterAlreadyBlocked(BlockedAppEntry.parseInstalledList(resp));if(apps.size()==0){toast(resp.startsWith("Error")?resp:"No apps available to block");return;}String[] labels=new String[apps.size()];for(int i=0;i<apps.size();i++)labels[i]=apps.get(i).displayName();new AlertDialog.Builder(this).setTitle("Block app").setItems(labels,(d,which)->{BlockedAppEntry e=apps.get(which);cmdWithCallback("block_app",e.pkg,ok->{toast("Blocked");getSharedPreferences("p",0).edit().remove("cachedInstalledApps").apply();showBlockedAppsScreen();},err->{toast("Block failed");});}).show();}
    void preloadInstalledApps(TextView status){status.setText("Loading child app list...");cmdWithCallback("list_apps","",resp->{if(resp.startsWith("Error")){status.setText(resp);return;}getSharedPreferences("p",0).edit().putString("cachedInstalledApps",resp).putLong("cachedInstalledAppsAt",System.currentTimeMillis()).apply();ArrayList<BlockedAppEntry> apps=BlockedAppEntry.parseInstalledList(resp);status.setText(apps.size()+" apps loaded from child");},err->{status.setText("Could not load child apps: "+err);});}
    void preloadInstalledApps(TextView status,LinearLayout installedList){status.setText("Loading child app list...");cmdWithCallback("list_apps","",resp->{if(resp.startsWith("Error")){status.setText(resp);installedList.removeAllViews();installedList.addView(tv(resp,14));return;}getSharedPreferences("p",0).edit().putString("cachedInstalledApps",resp).putLong("cachedInstalledAppsAt",System.currentTimeMillis()).apply();ArrayList<BlockedAppEntry> apps=BlockedAppEntry.parseInstalledList(resp);status.setText(apps.size()+" apps loaded from child");renderInstalledAppsForBlocking(installedList,resp);},err->{status.setText("Could not load child apps: "+err);});}
    void loadBlockedAppsList(LinearLayout list){cmdWithCallback("blocked_apps","",resp->{list.removeAllViews();ArrayList<BlockedAppEntry> apps=BlockedAppEntry.parseList(resp);rememberBlockedPackages(apps);if(apps.size()==0){list.addView(tv(tr(R.string.no_blocked_apps),15));return;}for(BlockedAppEntry e:apps){LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);TextView name=tv(e.displayName()+(e.untilText.length()>0?"\n"+e.untilText:""),14);Button remove=btn(tr(R.string.remove));row.addView(name,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));row.addView(remove);list.addView(row);remove.setOnClickListener(v->cmdWithCallback("unblock_app",e.pkg,ok->{toast("Removed");getSharedPreferences("p",0).edit().remove("cachedInstalledApps").apply();showBlockedAppsScreen();},err->{toast("Remove failed");out(err);}));}},err->{list.removeAllViews();list.addView(tv("Could not load blocked apps",15));out(err);});}
    void rememberBlockedPackages(ArrayList<BlockedAppEntry> apps){StringBuilder sb=new StringBuilder();for(BlockedAppEntry e:apps){if(e.pkg.length()>0)sb.append(e.pkg).append("\n");}getSharedPreferences("p",0).edit().putString("cachedBlockedPackages",sb.toString()).apply();}
    ArrayList<BlockedAppEntry> filterAlreadyBlocked(ArrayList<BlockedAppEntry> apps){String raw=getSharedPreferences("p",0).getString("cachedBlockedPackages","");HashSet<String> blocked=new HashSet<>();for(String row:raw.split("\\n")){String pkg=row.trim();if(pkg.length()>0)blocked.add(pkg);}ArrayList<BlockedAppEntry> out=new ArrayList<>();for(BlockedAppEntry e:apps){if(!blocked.contains(e.pkg))out.add(e);}return out;}


    void showUserMenu(){if(sidePanel!=null&&sidePanel.isShowing()){sidePanel.dismiss();return;}SharedPreferences prefs=getSharedPreferences("p",0);String role=prefs.getString("role","");boolean child="child".equals(role);boolean childConnected=prefs.getBoolean("childConnected",false)||prefs.getBoolean("childLinked",false);LinearLayout panel=menuPanel(child?tr(R.string.menu_child_device):"Menu");String[] actions=child?(childConnected?new String[]{"child_home","child_requests","quick_chat","permissions","settings"}:new String[]{"child_home","change_mode"}):new String[]{"dashboard","devices","profiles","logs","settings","exit_parent_monitor"};for(int i=0;i<actions.length;i++){String action=actions[i];Button b=menuButton(action);panel.addView(b);b.setOnClickListener(v->{if(sidePanel!=null)sidePanel.dismiss();handleMenuAction(action);});if(i<actions.length-1)panel.addView(menuDivider());}TextView version=UiFactory.mutedText(this,"Parental-Link v"+APP_VERSION,12);version.setGravity(Gravity.CENTER);panel.addView(version);showPanel(panel,Gravity.LEFT|Gravity.TOP);}
    LinearLayout menuPanel(String title){LinearLayout panel=new LinearLayout(this);panel.setOrientation(LinearLayout.VERTICAL);panel.setPadding(UiFactory.dp(this,16),UiFactory.dp(this,42),UiFactory.dp(this,16),UiFactory.dp(this,24));panel.setBackgroundColor(UiFactory.menuBg(this));TextView t=tv(title,22);t.setTypeface(android.graphics.Typeface.DEFAULT_BOLD);t.setPadding(UiFactory.dp(this,10),0,UiFactory.dp(this,10),UiFactory.dp(this,12));panel.addView(t);return panel;}
    Button menuButton(String action){String label=menuLabel(action);String[] parts=label.split("\\n",2);String title=parts[0];String sub=parts.length>1?parts[1]:"";String drawable=menuIconDrawable(action);int res=drawable.length()>0?getResources().getIdentifier(drawable,"drawable",getPackageName()):0;String text=(res==0?menuIcon(action)+"  ":"")+title+(sub.length()>0?"\n"+sub:"");android.text.SpannableString span=new android.text.SpannableString(text);int titleStart=text.indexOf(title);span.setSpan(new android.text.style.StyleSpan(android.graphics.Typeface.BOLD),titleStart,titleStart+title.length(),0);span.setSpan(new android.text.style.RelativeSizeSpan(1.08f),titleStart,titleStart+title.length(),0);if(sub.length()>0){int subStart=text.indexOf(sub);span.setSpan(new android.text.style.RelativeSizeSpan(0.88f),subStart,subStart+sub.length(),0);span.setSpan(new android.text.style.ForegroundColorSpan(UiFactory.mutedTextColor(this)),subStart,subStart+sub.length(),0);}Button b=btn("");b.setText(span);if(res!=0){android.graphics.drawable.Drawable icon=getDrawable(res);if(icon!=null){icon.setTint(UiFactory.blue());icon.setBounds(0,0,UiFactory.dp(this,24),UiFactory.dp(this,24));b.setCompoundDrawables(icon,null,null,null);b.setCompoundDrawablePadding(UiFactory.dp(this,12));}}b.setGravity(Gravity.CENTER_VERTICAL|Gravity.LEFT);b.setTextAlignment(View.TEXT_ALIGNMENT_TEXT_START);b.setBackgroundColor(Color.TRANSPARENT);b.setTextColor(UiFactory.textColor(this));b.setTextSize(14);LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,UiFactory.dp(this,62));lp.setMargins(0,0,0,0);b.setLayoutParams(lp);return b;}
