    void showPanel(LinearLayout panel,int gravity){FrameLayout overlay=new FrameLayout(this);overlay.setBackgroundColor(Color.argb(145,0,0,0));int w=(int)(getResources().getDisplayMetrics().widthPixels*0.88f);FrameLayout.LayoutParams plp=new FrameLayout.LayoutParams(w,ViewGroup.LayoutParams.MATCH_PARENT,gravity);overlay.addView(panel,plp);overlay.setOnClickListener(v->{if(sidePanel!=null)sidePanel.dismiss();});panel.setOnClickListener(v->{});sidePanel=new PopupWindow(overlay,ViewGroup.LayoutParams.MATCH_PARENT,ViewGroup.LayoutParams.MATCH_PARENT,true);sidePanel.setBackgroundDrawable(new android.graphics.drawable.ColorDrawable(Color.TRANSPARENT));sidePanel.setOutsideTouchable(true);sidePanel.showAtLocation(root,Gravity.LEFT|Gravity.TOP,0,0);}
    String menuLabel(String action){if(action.equals("dashboard"))return "Dashboard\n"+new DeviceProfile(this).childNickname();if(action.equals("child_home"))return "Home\nReturn to child dashboard";if(action.equals("change_mode"))return "Change mode\nChoose parent or child setup";if(action.equals("child_requests"))return "Requests\nView requests to parent";if(action.equals("permissions"))return "Check permissions\nReview required access";if(action.equals("language"))return "Application Language\nChoose app language";if(action.equals("ping"))return "Ring device\nPlay a loud sound on the child device";if(action.equals("media_volume"))return "Media volume\nAdjust media volume";if(action.equals("mute_toggle"))return getSharedPreferences("p",0).getBoolean("parentMediaMuted",false)?"Unmute\nRestore media sound":"Mute\nMute media sound";if(action.equals("enable_device"))return "Enable device\nTurn on normal access";if(action.equals("stop_timeout"))return "Stop timeout\nEnd the current timeout";if(action.equals("disable_use"))return "Block device\nBlock device use";if(action.equals("lock_timeout"))return "Timeout\nStart a timed break";if(action.equals("remove_all_limitations"))return "Remove all limitations\nLift restrictions temporarily";if(action.equals("free_use_now"))return "Free use now\nGrant free use";if(action.equals("interface_settings"))return "Interface settings\nChoose custom dashboard actions";if(action.equals("notification_settings"))return "Notification settings\nAllow noisy parent alerts";if(action.equals("devices"))return tr(R.string.menu_devices)+"\nManage child devices";if(action.equals("blocked_apps"))return tr(R.string.menu_blocked_apps)+"\nLimits, timeouts and blocks";if(action.equals("quick_chat"))return "Chat\nSend a message";if(action.equals("command_history"))return tr(R.string.menu_command_history)+"\nView sent commands";if(action.equals("logs"))return tr(R.string.menu_logs)+"\nActivity and system logs";if(action.equals("troubleshooting"))return tr(R.string.menu_troubleshooting)+"\nCheck this child device";if(action.equals("updates"))return tr(R.string.menu_version_updates)+"\nCheck app version and updates";if(action.equals("profiles"))return tr(R.string.menu_profiles)+"\nSend to all devices";if(action.equals("profiles_device"))return tr(R.string.menu_profiles)+"\nSend to "+new DeviceProfile(this).childNickname();if(action.equals("unlock_codes"))return tr(R.string.menu_unlock_codes)+"\nGenerate codes for this device";if(action.equals("settings"))return "Settings\nTheme, language and app options";if(action.equals("add_device"))return tr(R.string.menu_add_device);if(action.equals("exit_parent_monitor"))return tr(R.string.menu_exit_parent_monitor)+"\nStop monitoring service";if(action.equals("exit"))return tr(R.string.menu_exit);return action;}
    String menuIcon(String action){if(action.equals("dashboard"))return "\u2302";if(action.equals("devices"))return "\u25AF";if(action.equals("profiles")||action.equals("profiles_device"))return "\u25CE";if(action.equals("quick_chat"))return "\u25B6";if(action.equals("logs"))return "\u2630";if(action.equals("troubleshooting"))return "!";if(action.equals("unlock_codes"))return "#";if(action.equals("settings")||action.equals("interface_settings")||action.equals("language"))return "\u2699";if(action.equals("blocked_apps"))return "\u2298";if(action.equals("free_use_now")||action.equals("remove_all_limitations"))return "\u2713";if(action.equals("exit_parent_monitor"))return "\u2715";return "\u2022";}
    String menuIconDrawable(String action){if(action.equals("dashboard"))return "ic_menu_dashboard";if(action.equals("devices"))return "ic_menu_device";if(action.equals("profiles")||action.equals("profiles_device"))return "ic_menu_profile";if(action.equals("quick_chat"))return "ic_proto_chat";if(action.equals("logs"))return "ic_menu_logs";if(action.equals("troubleshooting"))return "ic_proto_question";if(action.equals("unlock_codes"))return "ic_menu_key";if(action.equals("settings")||action.equals("interface_settings")||action.equals("language"))return "ic_menu_settings";if(action.equals("blocked_apps"))return "ic_proto_lock";if(action.equals("free_use_now"))return "ic_menu_free";if(action.equals("remove_all_limitations"))return "ic_menu_escape";if(action.equals("exit_parent_monitor")||action.equals("exit"))return "ic_proto_power";if(action.equals("ping"))return "ic_proto_ping";if(action.equals("media_volume"))return "ic_proto_volume";if(action.equals("mute_toggle"))return getSharedPreferences("p",0).getBoolean("parentMediaMuted",false)?"ic_proto_volume":"ic_proto_mute";if(action.equals("lock_timeout")||action.equals("stop_timeout"))return "ic_proto_hourglass";if(action.equals("enable_device")||action.equals("disable_use"))return "ic_proto_power";return "";}
    String shortMenuLabel(String action){String m=menuLabel(action);int i=m.indexOf('\n');return i>=0?m.substring(0,i):m;}
    void showDeviceActionsMenu(){if(sidePanel!=null&&sidePanel.isShowing()){sidePanel.dismiss();return;}LinearLayout panel=menuPanel("Device Settings");boolean connected=childRecentlyConnected(getSharedPreferences("p",0));if(!connected)panel.addView(UiFactory.mutedText(this,"Connect to the child device before using device actions.",12));panel.addView(tv("Limits & access",13));String[] control={"profiles_device","blocked_apps","free_use_now","remove_all_limitations","unlock_codes","troubleshooting"};for(int i=0;i<control.length;i++){String action=control[i];Button b=menuButton(action);b.setEnabled(connected);b.setAlpha(connected?1f:0.45f);panel.addView(b);b.setOnClickListener(v->{if(!connected){toast("Connect to child first");searchForChildOnNetwork("Device menu action needs connection",true);return;}if(sidePanel!=null)sidePanel.dismiss();handleMenuAction(action);});if(i<control.length-1)panel.addView(menuDivider());}if(!parentAlertsAllowed()){panel.addView(tv("Notifications",13));Button alert=menuButton("notification_settings");panel.addView(menuDivider());panel.addView(alert);alert.setOnClickListener(v->{if(sidePanel!=null)sidePanel.dismiss();openAppNotificationSettings();});}showPanel(panel,Gravity.RIGHT|Gravity.TOP);}
