    RadioGroup themeModeRow(){RadioGroup group=new RadioGroup(this);group.setOrientation(RadioGroup.VERTICAL);String current=getSharedPreferences("p",0).getString("themeMode","dark");String[] labels={"Dark","Light","System"};String[] values={"dark","light","system"};for(int i=0;i<labels.length;i++){RadioButton rb=new RadioButton(this);rb.setId(View.generateViewId());rb.setText(labels[i]);rb.setTextColor(UiFactory.textColor(this));rb.setTag(values[i]);group.addView(rb);if(values[i].equals(current))group.check(rb.getId());}group.setOnCheckedChangeListener((g,id)->{RadioButton rb=g.findViewById(id);if(rb!=null){getSharedPreferences("p",0).edit().putString("themeMode",String.valueOf(rb.getTag())).apply();if("child_theme".equals(currentScreen))showChildThemeScreen();else showSettingsScreen();}});return group;}
