    void chooseQuickSlot(int slot){String[] actions={"Clear slot","Ring device","Media volume","Mute / unmute","Chat","Manage apps","Free use now","Remove all limitations","Devices","Profiles","Troubleshooting"};String[] values={"","ping","media_volume","mute_toggle","quick_chat","blocked_apps","free_use_now","remove_all_limitations","devices","profiles","troubleshooting"};new AlertDialog.Builder(this).setTitle("Quick action slot "+slot).setItems(actions,(d,which)->{getSharedPreferences("p",0).edit().putString("quickSlot"+slot,values[which]).apply();if("settings".equals(currentScreen))showSettingsScreen();else showJavaDashboardPrototype();}).show();}
    void attachDashboardSwipe(View v){if(v==null)return;v.setOnTouchListener((view,event)->{if(!"dashboard".equals(currentScreen))return false;switch(event.getAction()){case MotionEvent.ACTION_DOWN:swipeStartX=event.getX();swipeStartY=event.getY();return true;case MotionEvent.ACTION_UP:float dx=event.getX()-swipeStartX;float dy=event.getY()-swipeStartY;if(Math.abs(dx)>160&&Math.abs(dx)>Math.abs(dy)*1.6f){if(dx<0)showDeviceActionsMenu();else showUserMenu();return true;}return false;}return false;});}
    void handleMenuAction(String action){if(action.equals("dashboard"))showJavaDashboardPrototype();else if(action.equals("child_home"))showChild();else if(action.equals("change_mode"))changePairingMode();else if(action.equals("child_requests"))showChildAskParentScreen();else if(action.equals("permissions"))showChildSettingsGate();else if(action.equals("language"))showSettingsScreen();else if(action.equals("media_volume"))showVolumeScreen();else if(action.equals("mute_toggle"))toggleMediaMute();else if(action.equals("enable_device"))cmdWithCallback("enable_use","menu",resp->{setLocalLockState(false);setLocalTimeoutState(false);toast("Device enabled");showConnectedParent(false);},err->{toast("Enable failed");out(err);});else if(action.equals("disable_use"))cmdWithCallback("disable_use","24h",resp->{setLocalLockState(true);toast("Device disabled");showConnectedParent(false);},err->{toast("Disable failed");out(err);});else if(action.equals("stop_timeout"))cmdWithCallback("stop_timeout","menu",resp->{setLocalTimeoutState(false);toast("Timeout stopped");showConnectedParent(false);},err->{toast("Stop timeout failed");out(err);});else if(action.equals("lock_timeout"))showTimeoutDialog();else if(action.equals("remove_all_limitations"))confirmRemoveAllLimitationsCommand();else if(action.equals("logs")||action.equals("command_history"))showLogsScreen();else if(action.equals("troubleshooting"))showTroubleshootingScreen();else if(action.equals("updates"))showSettingsScreen();else if(action.equals("devices"))showDevicesScreen();else if(action.equals("add_device"))showParentConnection("");else if(action.equals("blocked_apps"))showBlockedAppsScreen();else if(action.equals("quick_chat"))showQuickChatScreen();else if(action.equals("ping"))cmd("ping","start");else if(action.equals("profiles")){getSharedPreferences("p",0).edit().putBoolean("profileSendAll",true).apply();showProfilesScreen();}else if(action.equals("profiles_device")){getSharedPreferences("p",0).edit().putBoolean("profileSendAll",false).apply();showProfilesScreen();}else if(action.equals("unlock_codes"))showUnlockCodesScreen();else if(action.equals("interface_settings")||action.equals("settings")){if("child".equals(getSharedPreferences("p",0).getString("role","")))showChildSettingsGate();else showSettingsScreen();}else if(action.equals("free_use_now"))cmdWithCallback("remove_all_limitations","free_use_now",resp->{setLocalLockState(false);setLocalTimeoutState(false);toast("Free use enabled");showConnectedParent(false);},err->{toast("Free use failed");out(err);});else if(action.equals("notification_settings"))openAppNotificationSettings();else if(action.equals("exit_parent_monitor"))stopParentMonitorAndExit();else if(action.equals("exit")){moveTaskToBack(true);}else toast(action+" will be added later");}
    void toggleMediaMute(){SharedPreferences p=getSharedPreferences("p",0);boolean muted=p.getBoolean("parentMediaMuted",false);if(muted)cmdWithCallback("volume","media|"+p.getInt("volume_current_media",50)+"|unmute",resp->{p.edit().putBoolean("parentMediaMuted",false).apply();toast("Unmuted");showJavaDashboardPrototype();},err->{toast("Unmute failed");out(err);});else cmdWithCallback("volume","media|0|mute",resp->{p.edit().putBoolean("parentMediaMuted",true).apply();toast("Muted");showJavaDashboardPrototype();},err->{toast("Mute failed");out(err);});}
    void stopParentMonitorAndExit(){try{stopService(new Intent(this,ParentMonitorService.class));}catch(Exception ignored){}try{NotificationManager nm=(NotificationManager)getSystemService(NOTIFICATION_SERVICE);if(nm!=null)nm.cancel(ParentMonitorService.NOTIFICATION_ID);}catch(Exception ignored){}addLog("Parent monitor stopped");toast("Parent monitor stopped");handler.postDelayed(()->{try{finishAndRemoveTask();}catch(Exception e){finish();}},250);}
    void showDevicesScreen(){base(tr(R.string.screen_devices));currentScreen="devices";SharedPreferences p=getSharedPreferences("p",0);String role=p.getString("role","");if("child".equals(role)){root.addView(sectionLabel(tr(R.string.parents)));root.addView(deviceListRow("\uD83D\uDC64",p.getString("parentName","Parent Control"),"Trusted parent",0,null,null));root.addView(menuDivider());root.addView(UiFactory.mutedText(this,"Only paired parents are shown here. Child devices are managed from the parent app.",13));return;}root.addView(sectionLabel(tr(R.string.parents)));root.addView(deviceListRow("\uD83D\uDC64",p.getString("parentName","Parent Control"),"This parent device",0,tr(R.string.add_parent),v->showAddParentScaffold()));root.addView(menuDivider());root.addView(sectionLabel("Device name"));DeviceProfile deviceProfile=new DeviceProfile(this);root.addView(deviceListRow(deviceIconEmoji(deviceProfile.childIcon()),deviceProfile.childNickname(),deviceProfile.childIp()+" - "+deviceHealthLine(),connectionStateColor(),"Edit",v->askDeviceDetails(false)));root.addView(menuDivider());root.addView(deviceActionRow("ic_proto_plus",tr(R.string.add_device),"Find or pair another child device",v->showParentConnection("")));root.addView(menuDivider());root.addView(deviceActionRow("ic_proto_lock",tr(R.string.remove),"Remove this child from the parent app",v->confirmRemoveChildDevice()));}
    LinearLayout deviceListRow(String icon,String title,String sub,int statusColor,String action,View.OnClickListener click){LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);row.setGravity(Gravity.CENTER_VERTICAL);row.setPadding(UiFactory.dp(this,8),UiFactory.dp(this,9),UiFactory.dp(this,8),UiFactory.dp(this,9));TextView iv=tv(deviceIconEmoji(icon),32);iv.setGravity(Gravity.CENTER);iv.setIncludeFontPadding(false);iv.setBackground(UiFactory.actionShape(this,UiFactory.panel(this),14,UiFactory.border(this)));LinearLayout.LayoutParams ilp=new LinearLayout.LayoutParams(UiFactory.dp(this,60),UiFactory.dp(this,60));ilp.setMargins(0,0,UiFactory.dp(this,12),0);row.addView(iv,ilp);LinearLayout bodyBox=new LinearLayout(this);bodyBox.setOrientation(LinearLayout.VERTICAL);TextView main=tv(title,16);main.setTypeface(android.graphics.Typeface.DEFAULT_BOLD);main.setSingleLine(true);TextView detail=UiFactory.mutedText(this,sub==null?"":sub,13);detail.setSingleLine(false);detail.setMaxLines(2);bodyBox.addView(main);bodyBox.addView(detail);row.addView(bodyBox,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));if(statusColor!=0){TextView dot=tv("",1);dot.setBackground(UiFactory.rounded(this,statusColor,99));LinearLayout.LayoutParams dlp=new LinearLayout.LayoutParams(UiFactory.dp(this,12),UiFactory.dp(this,12));dlp.setMargins(UiFactory.dp(this,8),0,UiFactory.dp(this,6),0);row.addView(dot,dlp);}if(action!=null){Button b=iconTextButton("Edit".equalsIgnoreCase(action)?"ic_proto_edit":"ic_proto_plus",action);LinearLayout.LayoutParams blp=new LinearLayout.LayoutParams(UiFactory.dp(this,92),UiFactory.dp(this,44));blp.setMargins(UiFactory.dp(this,8),0,0,0);row.addView(b,blp);b.setOnClickListener(click);}return row;}
    View deviceActionRow(String icon,String title,String sub,View.OnClickListener click){LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);row.setGravity(Gravity.CENTER_VERTICAL);row.setPadding(UiFactory.dp(this,8),UiFactory.dp(this,8),UiFactory.dp(this,8),UiFactory.dp(this,8));ImageView iv=new ImageView(this);int res=getResources().getIdentifier(icon,"drawable",getPackageName());iv.setImageResource(res!=0?res:R.drawable.ic_proto_question);iv.setColorFilter(UiFactory.blue());row.addView(iv,new LinearLayout.LayoutParams(UiFactory.dp(this,34),UiFactory.dp(this,34)));LinearLayout box=new LinearLayout(this);box.setOrientation(LinearLayout.VERTICAL);TextView t=tv(title,15);t.setTypeface(android.graphics.Typeface.DEFAULT_BOLD);TextView s=UiFactory.mutedText(this,sub,12);box.addView(t);box.addView(s);box.setPadding(UiFactory.dp(this,12),0,0,0);row.addView(box,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));TextView arrow=UiFactory.mutedText(this,">",18);arrow.setGravity(Gravity.CENTER);row.addView(arrow,new LinearLayout.LayoutParams(UiFactory.dp(this,24),UiFactory.dp(this,40)));row.setOnClickListener(click);return row;}
    int connectionStateColor(){SharedPreferences p=getSharedPreferences("p",0);long last=p.getLong("lastStatusMs",0);if(p.getBoolean("pairingMismatch",false))return UiFactory.red();if(last>0&&System.currentTimeMillis()-last<10L*60L*1000L)return UiFactory.green();return Color.rgb(120,130,145);}
    String deviceIconEmoji(String icon){return normalDeviceIcon(icon);}
    String normalDeviceIcon(String icon){String v=icon==null?"":icon.trim();if(v.length()==0)return "\uD83D\uDCFA";if(v.codePointCount(0,v.length())<=2&&!v.matches("[A-Za-z ]+"))return v;String low=v.toLowerCase(Locale.US);if(low.contains("phone"))return "\uD83D\uDCF2";if(low.contains("tablet"))return "\uD83D\uDCFA";if(low.contains("baby"))return "\uD83D\uDC76";if(low.contains("girl"))return "\uD83D\uDC67";if(low.contains("boy"))return "\uD83D\uDC66";if(low.contains("teen")||low.contains("kid")||low.contains("child"))return "\uD83E\uDDD2";if(low.contains("rainbow"))return "\uD83C\uDF08";if(low.contains("star"))return "\u2B50";if(low.contains("dog"))return "\uD83D\uDC36";if(low.contains("cat"))return "\uD83D\uDC31";if(low.contains("unicorn"))return "\uD83E\uDD84";return "\uD83D\uDCFA";}

    void showAddParentScaffold(){pendingSecureAction="add_parent";authPromptLaunched=false;showParentAppLock();}
    void showAddParentScaffoldUnlocked(){base("Add parent");currentScreen="add_parent";SharedPreferences p=getSharedPreferences("p",0);String invite=addParentInvitePayload();root.addView(tv("Add another parent",20));root.addView(UiFactory.mutedText(this,"Scan this QR with the second parent phone. It does not share the child encryption key; it only transfers parent setup context. The second parent must still pair with each child by QR/code.",14));ImageView qr=new ImageView(this);qr.setAdjustViewBounds(true);qr.setImageBitmap(qrBitmap(invite,260));LinearLayout.LayoutParams qlp=new LinearLayout.LayoutParams(UiFactory.dp(this,260),UiFactory.dp(this,260));qlp.gravity=Gravity.CENTER_HORIZONTAL;root.addView(qr,qlp);root.addView(tv("Parent: "+p.getString("parentName","Parent Control")+"\nDevice ID: "+p.getString("localDeviceId","")+"\nChild: "+new DeviceProfile(this).childNickname(),13));Button mark=btn("Mark second-parent setup pending");Button pair=btn("Open child pairing");Button back=btn("Back to Devices");root.addView(mark);root.addView(pair);root.addView(back);mark.setOnClickListener(v->{p.edit().putBoolean("secondParentSetupPending",true).putLong("secondParentSetupAt",System.currentTimeMillis()).apply();addLog("Security","Info","Second-parent setup pending","Waiting for parent 2 to complete child handshakes");toast("Second-parent setup marked pending");});pair.setOnClickListener(v->showParentConnection(""));back.setOnClickListener(v->showDevicesScreen());}
    String addParentInvitePayload(){SharedPreferences p=getSharedPreferences("p",0);return "family-link://add-parent?fromName="+Uri.encode(p.getString("parentName","Parent Control"))+"&fromId="+Uri.encode(p.getString("localDeviceId",""))+"&childName="+Uri.encode(new DeviceProfile(this).childNickname())+"&created="+System.currentTimeMillis();}
    void handleAddParentInvite(Uri u){String fromName=u.getQueryParameter("fromName");String fromId=u.getQueryParameter("fromId");String childName=u.getQueryParameter("childName");SharedPreferences p=getSharedPreferences("p",0);p.edit().putString("invitingParentName",fromName==null?"Parent 1":fromName).putString("invitingParentId",fromId==null?"":fromId).putString("pendingChildName",childName==null?"Child tablet":childName).putBoolean("secondParentInviteImported",true).apply();showSecondParentImportScreen();}
    void showSecondParentImportScreen(){base("Add parent");currentScreen="add_parent_import";SharedPreferences p=getSharedPreferences("p",0);root.addView(tv("Second parent setup",20));root.addView(UiFactory.mutedText(this,"Invitation from "+p.getString("invitingParentName","Parent 1")+". This phone will become a separate parent after it pairs with the child device. Commands are not mirrored between parents yet.",14));root.addView(tv("Child to pair: "+p.getString("pendingChildName","Child tablet"),15));Button pair=btn("Pair with child now");Button later=btn("Save and do later");root.addView(pair);root.addView(later);pair.setOnClickListener(v->{p.edit().putString("role","parent").apply();showParentConnection("");});later.setOnClickListener(v->{toast("Invitation saved");showStartOrSaved();});}

    void showQuickChatScreen(){base("Chat");currentScreen="quick_chat";final TextView status=tv("Refreshing recent messages...",13);root.addView(sectionLabel("Messages"));LinearLayout list=new LinearLayout(this);list.setOrientation(LinearLayout.VERTICAL);root.addView(list);String[][] presets={{"food","Come to eat"},{"clock","5 minutes"},{"quiet","Don't yell"},{"tidy","Tidy up"},{"bath","Bath time"},{"sleep","Bedtime"},{"phone","Call me"}};for(String[] preset:presets){Button b=menuButton("quick_chat");b.setText(preset[1]);b.setCompoundDrawablesWithIntrinsicBounds(ChatIcons.res(preset[0]),0,0,0);b.setCompoundDrawablePadding(UiFactory.dp(this,10));list.addView(b);b.setOnClickListener(v->showQuickMessageModeDialog(preset[0],preset[1],status));}Button custom=menuButton("quick_chat");custom.setText("+  Custom chat");custom.setCompoundDrawablesWithIntrinsicBounds(ChatIcons.res("chat"),0,0,0);custom.setCompoundDrawablePadding(UiFactory.dp(this,10));root.addView(custom);custom.setOnClickListener(v->showCustomQuickMessageDialog(status));root.addView(sectionLabel("Recent chat"));root.addView(status);refreshQuickMessageStatus(status);}
    void showQuickMessageModeDialog(String iconKey,String text,TextView status){String[] options={"Small banner for 5 minutes","Full-screen attention","Full-screen and block device"};new AlertDialog.Builder(this).setTitle(ChatIcons.titlePrefix(iconKey)+": "+text).setItems(options,(d,which)->{if(which==0)sendQuickMessage("banner",iconKey,text,5,false,status);else if(which==1)sendQuickMessage("full",iconKey,text,0,false,status);else sendQuickMessage("full",iconKey,text,0,true,status);}).show();}
    void showCustomQuickMessageDialog(TextView status){LinearLayout box=new LinearLayout(this);box.setOrientation(LinearLayout.VERTICAL);box.setPadding(UiFactory.dp(this,12),UiFactory.dp(this,8),UiFactory.dp(this,12),UiFactory.dp(this,8));EditText text=oneLine("Message, e.g. Come to eat");box.addView(text);new AlertDialog.Builder(this).setTitle("Custom chat").setView(box).setPositiveButton("Next",(d,w)->{String t=text.getText().toString().trim();if(t.length()==0){toast("Write a message first");return;}showQuickMessageModeDialog("chat",t,status);}).setNegativeButton("Cancel",null).show();}
    void sendQuickMessage(String mode,String iconKey,String text,int minutes,boolean block,TextView status){String safeIcon=ChatIcons.cleanKey(iconKey);String safeText=text.replace("|"," ").trim();String payload=mode+"|"+safeIcon+"|"+safeText+"|"+minutes+"|"+(block?"block":"normal");String quickId="chat_msg_"+System.currentTimeMillis();getSharedPreferences("p",0).edit().putString("lastQuickCommandId",quickId).putString("lastQuickCommandTitle",safeText).putString("lastQuickPayload",payload).putLong("quickChatFastPollUntil",System.currentTimeMillis()+60000L).apply();recordCommandStatus(quickId,"quick_chat","Sending","",payload);new CommandClient(this).send(childIp,key,"quick_chat",payload,resp->{recordCommandStatus(quickId,"quick_chat","Delivered",safeText,payload);toast("Chat sent");addLog("Activity","Info","Chat sent",safeText);status.setText("Sent: "+safeText+" ("+(mode.equals("banner")?"banner":"full screen")+(block?", blocking":"")+")");scheduleQuickMessageStatusPoll(status);},err->{recordCommandStatus(quickId,"quick_chat","Failed",err,payload);toast("Chat failed");addLog("Commands","Error","Chat failed",err);status.setText(err);});}
    void refreshQuickMessageStatus(TextView status){cmdWithCallback("chat_status","",resp->{status.setText(resp);updateQuickMessageStatusFromChild(resp);},err->{status.setText(err);out(err);});}
    void refreshQuickMessageStatusQuiet(){if(childIp==null||childIp.length()==0||key==null)return;cmdWithCallback("chat_status","",resp->{updateQuickMessageStatusFromChild(resp);},err->{});}
    void scheduleQuickMessageStatusPoll(TextView status){long[] delays={2000L,5000L,10000L,20000L,40000L,60000L};for(long d:delays)handler.postDelayed(()->{if(status!=null&&status.getParent()!=null)refreshQuickMessageStatus(status);else refreshQuickMessageStatusQuiet();},d);}
    void updateQuickMessageStatusFromChild(String resp){String compact=compactQuickMessageStatus(resp);if(compact.length()==0)return;getSharedPreferences("p",0).edit().putString("lastQuickChildStatus",compact).apply();}
    String compactQuickMessageStatus(String resp){if(resp==null)return "";String line="";for(String l:resp.split("\n")){if(l.startsWith("Child action:")){line=l.substring("Child action:".length()).trim();break;}}if(line.length()==0)return "";int dash=line.indexOf(" - ");String action=dash>=0?line.substring(dash+3).trim():line;int at=action.indexOf(" at ");if(at>=0)action=action.substring(0,at).trim();String low=action.toLowerCase(java.util.Locale.US);if(low.startsWith("dismissed"))return "Dismissed";if(low.startsWith("snoozed"))return "Snoozed";if(low.startsWith("expired"))return "Expired";if(low.startsWith("asked parent"))return "Asked unlock";return action.length()>0?action:"Updated";}

    String[] deviceIconChoices(){return new String[]{"\uD83D\uDCFA","\uD83D\uDCF2","\uD83D\uDC76","\uD83D\uDC67","\uD83D\uDC66","\uD83E\uDDD2","\uD83E\uDDD1","\uD83C\uDF08","\u2B50","\uD83D\uDC99","\uD83C\uDFAE","\uD83D\uDCDA","\uD83D\uDC31","\uD83D\uDC36","\uD83D\uDC3C","\uD83E\uDD8A","\uD83E\uDD84","\uD83C\uDF4E","\uD83C\uDF53","\uD83C\uDF4C","\uD83C\uDF49","\uD83C\uDF4A"};}
    void chooseDeviceIcon(String current,java.util.function.Consumer<String> picked){String[] icons=deviceIconChoices();GridLayout grid=new GridLayout(this);int columns=5;grid.setColumnCount(columns);grid.setPadding(UiFactory.dp(this,6),UiFactory.dp(this,6),UiFactory.dp(this,6),UiFactory.dp(this,6));int dialogWidth=Math.min(getResources().getDisplayMetrics().widthPixels-UiFactory.dp(this,48),UiFactory.dp(this,360));int cellSize=Math.max(UiFactory.dp(this,46),Math.min(UiFactory.dp(this,58),(dialogWidth-UiFactory.dp(this,12))/columns-UiFactory.dp(this,4)));AlertDialog dialog=new AlertDialog.Builder(this).setTitle("Device icon").setView(grid).create();for(String icon:icons){TextView cell=tv(icon,28);cell.setGravity(Gravity.CENTER);cell.setIncludeFontPadding(false);cell.setPadding(0,0,0,0);cell.setBackground(UiFactory.actionShape(this,normalDeviceIcon(current).equals(icon)?Color.rgb(214,232,255):UiFactory.panel(this),10,UiFactory.border(this)));GridLayout.LayoutParams lp=new GridLayout.LayoutParams();lp.width=cellSize;lp.height=cellSize;lp.setMargins(UiFactory.dp(this,2),UiFactory.dp(this,2),UiFactory.dp(this,2),UiFactory.dp(this,2));grid.addView(cell,lp);cell.setOnClickListener(v->{picked.accept(icon);dialog.dismiss();});}dialog.show();}
    void askDeviceDetails(boolean firstRun){base("Edit child device");currentScreen="device_edit";SharedPreferences p=getSharedPreferences("p",0);root.addView(sectionLabel("Device name"));LinearLayout nameRow=new LinearLayout(this);nameRow.setOrientation(LinearLayout.HORIZONTAL);TextView iconButton=tv(deviceIconEmoji(p.getString("childIcon","\uD83D\uDCFA")),30);iconButton.setGravity(Gravity.CENTER);iconButton.setBackground(UiFactory.actionShape(this,UiFactory.panel(this),12,UiFactory.border(this)));EditText nick=oneLine("Device name");nick.setText(p.getString("childNickname","Child tablet"));nameRow.addView(iconButton,new LinearLayout.LayoutParams(UiFactory.dp(this,54),UiFactory.dp(this,54)));nameRow.addView(nick,new LinearLayout.LayoutParams(0,UiFactory.dp(this,54),1));root.addView(nameRow);final String[] selectedIcon={deviceIconEmoji(p.getString("childIcon","\uD83D\uDCFA"))};iconButton.setOnClickListener(v->chooseDeviceIcon(selectedIcon[0],icon->{selectedIcon[0]=icon;iconButton.setText(icon);}));root.addView(menuDivider());root.addView(sectionLabel("Connection"));LinearLayout conn=new LinearLayout(this);conn.setOrientation(LinearLayout.HORIZONTAL);TextView info=tv("Saved IP: "+p.getString("childIp","not set")+"\nLast status: "+deviceLastStatusText()+"\nPairing: "+(p.getBoolean("pairingMismatch",false)?"possible mismatch":"normal"),14);LinearLayout tools=new LinearLayout(this);tools.setOrientation(LinearLayout.VERTICAL);Button test=iconTextButton("ic_proto_test","Test");Button repair=iconTextButton("ic_proto_repair","Repair");tools.addView(test,new LinearLayout.LayoutParams(UiFactory.dp(this,96),UiFactory.dp(this,44)));tools.addView(repair,new LinearLayout.LayoutParams(UiFactory.dp(this,96),UiFactory.dp(this,44)));conn.addView(info,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));conn.addView(tools);root.addView(conn);test.setOnClickListener(v->testChildConnection());repair.setOnClickListener(v->showRepairPairingScreen());root.addView(menuDivider());root.addView(sectionLabel("Language"));root.addView(languageOptions(true));root.addView(menuDivider());Button save=btn(tr(R.string.save));root.addView(save);save.setOnClickListener(v->{String name=nick.getText().toString().trim();if(name.length()==0)name="Child tablet";p.edit().putString("childNickname",name).putString("childIcon",selectedIcon[0]).apply();cmdWithCallback("set_child_icon",selectedIcon[0],ok->{},err->{});toast("Saved");showDevicesScreen();});}
    Button iconTextButton(String drawable,String label){Button b=btn(label);try{android.graphics.drawable.Drawable d=getResources().getDrawable(getResources().getIdentifier(drawable,"drawable",getPackageName()));d.setTint(UiFactory.blue());b.setCompoundDrawablesWithIntrinsicBounds(d,null,null,null);b.setCompoundDrawablePadding(UiFactory.dp(this,6));}catch(Exception ignored){}return b;}
    void promptMasterPasswordChange(){SharedPreferences p=getSharedPreferences("p",0);String current=p.getString("parentPassword","");LinearLayout box=new LinearLayout(this);box.setOrientation(LinearLayout.VERTICAL);EditText oldPass=oneLine("Current master password");oldPass.setInputType(InputType.TYPE_CLASS_NUMBER);oldPass.setFilters(new InputFilter[]{new InputFilter.LengthFilter(8)});if(current.length()>0)box.addView(oldPass);EditText newPass=oneLine("New master password (4-8 digits)");newPass.setInputType(InputType.TYPE_CLASS_NUMBER);newPass.setFilters(new InputFilter[]{new InputFilter.LengthFilter(8)});box.addView(newPass);new AlertDialog.Builder(this).setTitle("Change master password").setView(box).setNegativeButton("Cancel",null).setPositiveButton("Save",(d,w)->{String old=oldPass.getText().toString().trim();String pass=newPass.getText().toString().trim();if(current.length()>0&&!current.equals(old)){toast("Current password is wrong");return;}if(pass.length()<4||pass.length()>8){toast("Use 4 to 8 digits for the master password");return;}p.edit().putString("parentPassword",pass).putString("masterPassword",pass).putBoolean("masterPasswordSet",true).apply();cmdWithCallback("set_parent_password",p.getString("parentName","Parent Control")+"|"+pass,resp->{toast("Master password changed");askDeviceDetails(false);},err->{toast("Saved locally. Child update failed.");askDeviceDetails(false);});}).show();}

    String deviceLastStatusText(){long last=getSharedPreferences("p",0).getLong("lastStatusMs",0);if(last<=0)return "never";long min=(System.currentTimeMillis()-last)/60000;return min<=0?"just now":min+" min ago";}
    String deviceHealthLine(){SharedPreferences p=getSharedPreferences("p",0);if(p.getBoolean("pairingMismatch",false))return "Repair pairing needed";long last=p.getLong("lastStatusMs",0);if(last<=0)return "No child status yet";long min=(System.currentTimeMillis()-last)/60000;if(min>10)return "Stale - last sync "+elapsedMinutesText(min)+" ago";return "Online - last sync "+(min<=0?"just now":elapsedMinutesText(min)+" ago");}
    void clearChildStatusOnly(){getSharedPreferences("p",0).edit().remove("remoteVersion").remove("remoteProtocol").remove("remotePermissions").remove("remoteCapabilities").remove("remoteDnd").remove("lastCurrentApp").remove("lastStatusMs").remove("todayMinutes").remove("remoteBattery").remove("remoteCharging").remove("remoteWifiBars").remove("devicesNotificationSummary").remove("pairingMismatch").remove("pairingMismatchMessage").apply();addLog("Connection","Info","Child status cleared","Waiting for a fresh encrypted status update");}
    void testChildConnection(){cmdWithCallback("hello","",resp->{toast("Child responded");addLog("Connection","Info","Child connection test",resp);getSharedPreferences("p",0).edit().putBoolean("pairingMismatch",false).remove("pairingMismatchMessage").remove("pairingMismatchReason").apply();askDeviceDetails(false);},err->{toast("Connection test failed");addLog("Connection","Error","Child connection test failed",err);if(getSharedPreferences("p",0).getBoolean("pairingMismatch",false))showPairingRecoveryScreen();else askDeviceDetails(false);});}
