    void showPairingRecoveryScreen(){base("Connection recovery");currentScreen="pairing_recovery";SharedPreferences p=getSharedPreferences("p",0);String msg=p.getString("pairingMismatchMessage",p.getString("pairingMismatchReason","A device answered at the saved address, but encrypted pairing did not complete."));root.addView(tv("Device found, but pairing no longer matches.",18));root.addView(UiFactory.mutedText(this,msg,14));root.addView(UiFactory.mutedText(this,"The child app may have been reset, reinstalled, data-cleared, or the IP may now belong to another device. No pairing data will be reset automatically.",13));Button retry=btn("Retry encrypted connection");Button repair=btn("Repair by child QR/code");Button reset=btn("Reset local pairing");Button back=btn("Back");root.addView(retry);root.addView(repair);root.addView(reset);root.addView(back);retry.setOnClickListener(v->cmdWithCallback("hello","",resp->{toast("Encrypted connection restored");addLog("Connection","Info","Pairing recovery retry succeeded",resp);getSharedPreferences("p",0).edit().putBoolean("pairingMismatch",false).remove("pairingMismatchMessage").remove("pairingMismatchReason").apply();showJavaDashboardPrototype();},err->{toast("Still not matching");addLog("Connection","Warning","Pairing recovery retry failed",err);}));repair.setOnClickListener(v->showRepairPairingScreen());reset.setOnClickListener(v->confirmResetLocalPairing());back.setOnClickListener(v->showJavaDashboardPrototype());root.addView(log);}
    void confirmResetLocalPairing(){SharedPreferences p=getSharedPreferences("p",0);String saved=p.getString("parentPassword",p.getString("masterPassword",""));LinearLayout box=new LinearLayout(this);box.setOrientation(LinearLayout.VERTICAL);TextView warning=UiFactory.mutedText(this,"This only removes this parent phone's saved child connection. It does not remove Parental-Link from the child tablet.",14);box.addView(warning);EditText pass=oneLine(saved.length()>0?"Master password":"Type RESET");pass.setInputType(saved.length()>0?InputType.TYPE_CLASS_NUMBER:InputType.TYPE_CLASS_TEXT);box.addView(pass);new AlertDialog.Builder(this).setTitle("Reset local pairing?").setView(box).setNegativeButton("Cancel",null).setPositiveButton("Reset",(d,w)->{String entered=pass.getText().toString().trim();if(saved.length()>0&&!saved.equals(entered)){toast("Wrong password");return;}if(saved.length()==0&&!entered.equals("RESET")){toast("Type RESET to confirm");return;}resetLocalChildPairingOnly();}).show();}
    void resetLocalChildPairingOnly(){getSharedPreferences("p",0).edit().remove("childIp").remove("parentKey").remove("childNickname").remove("childIcon").remove("remoteVersion").remove("remoteProtocol").remove("remotePermissions").remove("remoteCapabilities").remove("remoteDnd").remove("lastCurrentApp").remove("lastCurrentPackage").remove("lastStatusMs").remove("todayMinutes").remove("remoteBattery").remove("remoteCharging").remove("remoteWifiBars").remove("devicesNotificationSummary").remove("pairingMismatch").remove("pairingMismatchMessage").remove("pairingMismatchReason").remove("pairingMismatchAt").remove("childUnlockRequestPending").remove("childUnlockRequestReason").remove("childUnlockRequestAt").remove("childUnlockSnoozeUntil").putBoolean("childDeviceRemoved",true).apply();childIp="";key=null;addLog("Security","Warning","Local child pairing reset","Reset was confirmed on parent device");toast("Local pairing reset");showStartOrSaved();}
