    void showRepairPairingScreen(String prefillCode,String prefillIp){base("Repair pairing");currentScreen="repair_pairing";root.addView(tv("Use this if the child app was reset, the IP belongs to another device, or the saved pairing is stale.",15));EditText ip=oneLine("Child IP address");ip.setText(prefillIp==null?"":prefillIp);EditText code=oneLine("New pairing code");code.setInputType(InputType.TYPE_CLASS_NUMBER);if(prefillCode!=null&&prefillCode.length()>0)code.setText(prefillCode.replaceAll("\\D",""));root.addView(ip);root.addView(code);Button scan=btn("Scan QR");Button repair=btn("Repair pairing");Button back=btn("Back");root.addView(scan);root.addView(repair);root.addView(back);scan.setOnClickListener(v->startQrScanSafely());repair.setOnClickListener(v->{String newIp=ip.getText().toString().trim();String newCode=code.getText().toString().trim();if(newIp.length()==0||newCode.length()==0){toast("Enter child IP and code");return;}clearChildStatusOnly();pairWithChild(newIp,newCode);});back.setOnClickListener(v->showPairingRecoveryScreen());root.addView(log);}

    void showLanguageScreen(boolean targetChild){base("Language");currentScreen=targetChild?"child_language":"language";SharedPreferences p=getSharedPreferences("p",0);String current=targetChild?p.getString("childLanguage","system"):LanguageManager.current(this);root.addView(tv(targetChild?tr(R.string.screen_language_child):tr(R.string.screen_language_app),18));root.addView(tv(tr(R.string.language_help),13));RadioGroup group=new RadioGroup(this);group.setOrientation(RadioGroup.VERTICAL);String[] values={"system","en","el","fr"};for(String val:values){RadioButton rb=new RadioButton(this);rb.setId(View.generateViewId());rb.setText(LanguageManager.label(val));rb.setTextColor(UiFactory.textColor(this));rb.setTag(val);group.addView(rb);if(val.equals(current))group.check(rb.getId());}root.addView(group);Button save=btn(tr(R.string.save));root.addView(save);save.setOnClickListener(v->{RadioButton rb=group.findViewById(group.getCheckedRadioButtonId());String lang=rb==null?"system":String.valueOf(rb.getTag());if(targetChild){p.edit().putString("childLanguage",lang).apply();cmdWithCallback("set_language",lang,resp->{toast(tr(R.string.child_language_saved));showDevicesScreen();},err->{toast(tr(R.string.saved_locally_child_failed));showDevicesScreen();});}else{LanguageManager.set(this,lang);toast(tr(R.string.language_saved));recreate();}});}

    void confirmRemoveChildDevice(){SharedPreferences p=getSharedPreferences("p",0);String child=p.getString("childNickname","Child tablet");String master=p.getString("parentPassword","");String msg="Remove "+child+" from this parent app?";new AlertDialog.Builder(this).setTitle("Remove child device?").setMessage(msg+"\n\nIf the child is online, Parental-Link will remove the parent link from the child first. If it is offline, write down the child master password before removing it locally.\n\nMaster password: "+(master.length()>0?master:"not set")).setNegativeButton("Cancel",null).setPositiveButton("Continue",(d,w)->tryRemoveChildDeviceOnline()).show();}

    void tryRemoveChildDeviceOnline(){cmdWithCallback("remove_parental_link","parent_removed",resp->{addLog("Security","Info","Child removal requested",resp);getSharedPreferences("p",0).edit().putBoolean("childRemovalPending",true).putString("childRemovalStatus",resp).apply();toast("Removal request sent. Authorise on child device.");showSafeDashboardJava();},err->{showOfflineChildRemovalWarning(err);});}

    void showOfflineChildRemovalWarning(String err){String master=getSharedPreferences("p",0).getString("parentPassword","");AlertDialog dlg=new AlertDialog.Builder(this).setTitle("Child device is offline").setMessage("The child device did not acknowledge removal. Removing it now may leave Parental-Link active on the child device.\n\nWrite down the child master password and use it on the child device: Unlock settings > Remove Parental-Link settings.\n\nMaster password: "+(master.length()>0?master:"not set")+"\n\nError: "+err).setNegativeButton("Cancel",null).setPositiveButton("Remove locally in 5",null).create();dlg.setOnShowListener(di->{Button b=dlg.getButton(AlertDialog.BUTTON_POSITIVE);b.setEnabled(false);final int[] r={5};Runnable tick=new Runnable(){public void run(){if(!dlg.isShowing())return;if(r[0]>0){b.setText("Remove locally in "+r[0]);r[0]--;handler.postDelayed(this,1000);}else{b.setText("Remove locally");b.setEnabled(true);}}};tick.run();b.setOnClickListener(v->{dlg.dismiss();removeChildLocally();});});dlg.show();}

    void removeChildLocally(){getSharedPreferences("p",0).edit()
            .remove("childIp").remove("parentKey").remove("childNickname").remove("childIcon")
            .remove("remoteVersion").remove("remoteProtocol").remove("remotePermissions")
            .remove("remoteCapabilities").remove("remoteDnd").remove("lastCurrentApp")
            .remove("lastStatusMs").remove("todayMinutes").remove("remoteBattery")
            .remove("remoteCharging").remove("remoteWifiBars").remove("devicesNotificationSummary")
            .remove("childRemovalRequested").remove("childRemovalMethod").remove("childRemovalPending").remove("pairingMismatch").remove("pairingMismatchMessage").remove("childUnlockRequestPending").remove("childUnlockRequestReason").remove("childUnlockRequestAt").remove("childUnlockSnoozeUntil")
            .putBoolean("childDeviceRemoved",true)
            .apply();
        addLog("Security","Info","Child device removal cleanup","Local child status cleared");
        addLog("Security","Info","Child device removed locally","Parent app removed saved child connection");
        toast("Child device removed");showStartOrSaved();}
    void showProfilesScreen(){base("Profiles");currentScreen="profiles";SharedPreferences p=getSharedPreferences("p",0);boolean all=p.getBoolean("profileSendAll",false);root.addView(sectionLabel("Send profile to"));LinearLayout target=new LinearLayout(this);target.setOrientation(LinearLayout.HORIZONTAL);Button current=all?btn(new DeviceProfile(this).childNickname()):UiFactory.primaryButton(this,new DeviceProfile(this).childNickname());Button allDevices=all?UiFactory.primaryButton(this,"All devices"):btn("All devices");target.addView(current,new LinearLayout.LayoutParams(0,UiFactory.dp(this,44),1));target.addView(allDevices,new LinearLayout.LayoutParams(0,UiFactory.dp(this,44),1));root.addView(target);current.setOnClickListener(v->{p.edit().putBoolean("profileSendAll",false).apply();showProfilesScreen();});allDevices.setOnClickListener(v->{p.edit().putBoolean("profileSendAll",true).apply();showProfilesScreen();});root.addView(sectionLabel("Profiles"));Button homework=menuButton("profiles");homework.setText("Homework mode");Button bedtime=menuButton("profiles");bedtime.setText("Bedtime mode");Button free=menuButton("profiles");free.setText("Free use: remove all limitations");root.addView(homework);root.addView(bedtime);root.addView(free);homework.setOnClickListener(v->sendProfile("homework"));bedtime.setOnClickListener(v->sendProfile("bedtime"));free.setOnClickListener(v->confirmRemoveAllLimitationsCommand());}
