    void showLogsScreen(){base("Logs");currentScreen="logs";SharedPreferences p=getSharedPreferences("p",0);final String[] currentFilter={"All"};final boolean[] full={false};LinearLayout controls=new LinearLayout(this);controls.setOrientation(LinearLayout.HORIZONTAL);Button type=btn("Type: All");Button view=btn("View: One line");Button more=btn("\u22EE");controls.addView(type,new LinearLayout.LayoutParams(0,UiFactory.dp(this,48),1));controls.addView(view,new LinearLayout.LayoutParams(0,UiFactory.dp(this,48),1));controls.addView(more,new LinearLayout.LayoutParams(UiFactory.dp(this,48),UiFactory.dp(this,48)));root.addView(controls);LinearLayout list=new LinearLayout(this);list.setOrientation(LinearLayout.VERTICAL);root.addView(list);String[] types={"All","Activity","Security","Connection","Commands","Debug"};type.setOnClickListener(v->showSmallMenu(type,types,item->{currentFilter[0]=item;type.setText("Type: "+item);renderLogsListRows(list,p.getString("logs",""),currentFilter[0],full[0]);}));view.setOnClickListener(v->showSmallMenu(view,new String[]{"One line","Full"},item->{full[0]="Full".equals(item);view.setText("View: "+item);renderLogsListRows(list,p.getString("logs",""),currentFilter[0],full[0]);}));more.setOnClickListener(v->showSmallMenu(more,new String[]{"Clear logs"},item->new AlertDialog.Builder(this).setTitle("Clear logs?").setMessage("This will remove the event history from this device.").setNegativeButton("Cancel",null).setPositiveButton("Clear",(dd,w)->{getSharedPreferences("p",0).edit().remove("logs").remove("latestLog").apply();showLogsScreen();}).show()));renderLogsListRows(list,p.getString("logs",""),"All",false);}
    void renderLogsListRows(LinearLayout list,String raw,String filter,boolean full){list.removeAllViews();if(raw==null||raw.trim().length()==0){list.addView(tv("No logs yet",15));return;}for(String line:raw.split("\n")){if(line.trim().length()==0)continue;if(!"All".equals(filter)&&!line.contains("["+filter+"/"))continue;TextView row=UiFactory.mutedText(this,full?AppLog.detail(line):AppLog.lineSummary(line),14);row.setSingleLine(!full);row.setEllipsize(TextUtils.TruncateAt.END);row.setGravity(Gravity.CENTER_VERTICAL);row.setPadding(UiFactory.dp(this,8),0,UiFactory.dp(this,8),0);row.setBackgroundColor(Color.TRANSPARENT);LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,full?ViewGroup.LayoutParams.WRAP_CONTENT:UiFactory.dp(this,42));lp.setMargins(0,0,0,0);row.setLayoutParams(lp);row.setOnClickListener(v->new AlertDialog.Builder(this).setTitle("Log details").setMessage(AppLog.detail(line)).setPositiveButton("OK",null).show());list.addView(row);list.addView(menuDivider());}}
    void showSmallMenu(View anchor,String[] items,Ok choose){LinearLayout box=new LinearLayout(this);box.setOrientation(LinearLayout.VERTICAL);box.setBackground(UiFactory.rounded(this,UiFactory.menuBg(this),12));box.setPadding(UiFactory.dp(this,6),UiFactory.dp(this,6),UiFactory.dp(this,6),UiFactory.dp(this,6));PopupWindow pop=new PopupWindow(box,UiFactory.dp(this,190),ViewGroup.LayoutParams.WRAP_CONTENT,true);for(String item:items){Button b=menuButton("logs");b.setText(item);box.addView(b,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,UiFactory.dp(this,44)));b.setOnClickListener(v->{pop.dismiss();choose.call(item);});}pop.setBackgroundDrawable(new android.graphics.drawable.ColorDrawable(Color.TRANSPARENT));pop.setOutsideTouchable(true);pop.showAsDropDown(anchor,0,UiFactory.dp(this,2));}
    void renderLogsList(String raw,String filter,boolean full){while(root.getChildCount()>4)root.removeViewAt(4);if(raw==null||raw.trim().length()==0){root.addView(tv("No logs yet",15));return;}String[] lines=raw.split("\n");for(String line:lines){if(line.trim().length()==0)continue;if(!"All".equals(filter)&&!line.contains("["+filter+"/"))continue;TextView row=tv(full?AppLog.detail(line):AppLog.lineSummary(line),14);row.setSingleLine(!full);row.setEllipsize(TextUtils.TruncateAt.END);row.setOnClickListener(v->new AlertDialog.Builder(this).setTitle("Log details").setMessage(AppLog.detail(line)).setPositiveButton("OK",null).show());root.addView(row);} }


    void showCommandHistoryScreen(){base(tr(R.string.command_history_title));currentScreen="command_history";root.addView(tv(tr(R.string.command_history_help),14));LinearLayout list=new LinearLayout(this);list.setOrientation(LinearLayout.VERTICAL);root.addView(list,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,0,1));renderCommandHistoryRows(list);LinearLayout actions=new LinearLayout(this);actions.setOrientation(LinearLayout.HORIZONTAL);Button clear=btn(tr(R.string.clear));Button refresh=btn(tr(R.string.refresh));actions.addView(clear,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));actions.addView(refresh,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));root.addView(actions);clear.setOnClickListener(v->{CommandStatusStore.clear(this);showCommandHistoryScreen();});refresh.setOnClickListener(v->showCommandHistoryScreen());}
    void renderCommandHistoryRows(LinearLayout list){list.removeAllViews();String raw=getSharedPreferences("p",0).getString("commandLifecycleHistory","");if(raw.trim().length()==0){list.addView(tv("No command history",15));return;}java.text.SimpleDateFormat fmt=new java.text.SimpleDateFormat("HH:mm:ss",java.util.Locale.US);for(String row:raw.split("\\n")){String[] p=row.split("\\|",-1);if(p.length<4)continue;long t=0;try{t=Long.parseLong(p[0]);}catch(Exception ignored){}String time=t>0?fmt.format(new java.util.Date(t)):"--:--";String command=p[2];String status=p[3];String details=p.length>4?p[4]:"";String value=p.length>5?p[5]:"";LinearLayout line=new LinearLayout(this);line.setOrientation(LinearLayout.HORIZONTAL);TextView item=tv(time+"  "+(command.equals("quick_chat")?compactActivityLine(command,status,details,value):commandIcon(command,status)+" "+command+" - "+status+(details.length()>0?"\\n"+shortText(details,90):"")),13);line.addView(item,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));if("Failed".equalsIgnoreCase(status)){Button retry=btn("Retry");line.addView(retry);retry.setOnClickListener(v->{cmdWithCallback(command,value,resp->{toast(tr(R.string.retry_executed));showCommandHistoryScreen();},err->{toast(tr(R.string.retry_failed));showCommandHistoryScreen();});});}line.setOnClickListener(v->new AlertDialog.Builder(this).setTitle(command+" - "+status).setMessage("Time: "+time+"\\nDetails: "+details+"\\nValue: "+value).setPositiveButton("OK",null).show());list.addView(line);}}
    String commandIcon(String command,String status){String s=(command+" "+status).toLowerCase(java.util.Locale.US);if(s.contains("failed"))return "X";if(s.contains("sending"))return "...";if(s.contains("ping"))return "PING";if(s.contains("timeout"))return "TIME";if(s.contains("disable")||s.contains("lock"))return "LOCK";if(s.contains("volume"))return "VOL";if(s.contains("mute"))return "MUTE";if(s.contains("chat")||s.contains("message"))return "MSG";if(s.contains("call"))return "CALL";if(s.contains("block"))return "BLOCK";return "OK";}
    String shortText(String s,int max){if(s==null)return "";return s.length()<=max?s:s.substring(0,Math.max(0,max-3))+"...";}

    void showTroubleshootingScreen(){
        base("Troubleshooting");currentScreen="troubleshooting";SharedPreferences p=getSharedPreferences("p",0);String role=p.getString("role","");
        if("child".equals(role)){
            root.addView(sectionLabel("Child device"));
            root.addView(diagnosticRow("Server","running","\u2713","Child service"));
            root.addView(diagnosticRow("Device admin",isDeviceAdminActive()?"Enabled":"Needed",isDeviceAdminActive()?"\u2713":"X","Screen lock"));
            root.addView(diagnosticRow("App usage access",hasUsageAccess()?"Enabled":"Needed",hasUsageAccess()?"\u2713":"X","Current app"));
            root.addView(diagnosticRow("Accessibility",isAccessibilityEnabled()?"Enabled":"Needed",isAccessibilityEnabled()?"\u2713":"X","App blocking"));
            root.addView(diagnosticRow("Notifications",hasNotificationPermission()?"Enabled":"Needed",hasNotificationPermission()?"\u2713":"X","Alerts"));
            root.addView(diagnosticRow("Camera",hasCameraPermission()?"Enabled":"Needed",hasCameraPermission()?"\u2713":"X","QR pairing and future visual checks"));
            root.addView(diagnosticRow("Microphone",hasMicrophonePermission()?"Enabled":"Needed",hasMicrophonePermission()?"\u2713":"X","Chat audio and future voice checks"));
            root.addView(diagnosticRow("Draw over apps",hasOverlayPermission()?"Enabled":"Needed",hasOverlayPermission()?"\u2713":"X","Prompts"));
            Button logs=menuButton("logs");logs.setText("Open logs");Button restart=menuButton("troubleshooting");restart.setText("Restart server");root.addView(logs);root.addView(restart);logs.setOnClickListener(v->showLogsScreen());restart.setOnClickListener(v->startChildService());return;
        }
        root.addView(sectionLabel("Parent phone"));
        root.addView(diagnosticRow("Local network",getIp()!=null&&getIp().length()>0?getIp():"Unknown",getIp()!=null&&getIp().length()>0?"\u2713":"?","This phone"));
        root.addView(diagnosticRow("Saved child",childIp.length()>0?childIp:"Not saved",childIp.length()>0?"\u2713":"?","Last known address"));
        root.addView(diagnosticRow("Pairing",p.getBoolean("pairingMismatch",false)?"Repair needed":"Looks good",p.getBoolean("pairingMismatch",false)?"X":"\u2713",p.getBoolean("pairingMismatch",false)?p.getString("pairingMismatchReason","Saved pairing did not match"):"Encrypted key saved"));
        root.addView(sectionLabel(new DeviceProfile(this).childNickname()));
        long last=p.getLong("lastStatusMs",0);long age=last>0?(System.currentTimeMillis()-last)/60000:-1;boolean connected=last>0&&age<30;String checked=lastCheckedText(last);
        root.addView(diagnosticRow("Connection",connected?(age<1?"Just now":elapsedMinutesText(age)+" ago"):checked,connected?"\u2713":"?","Encrypted heartbeat"));
        root.addView(diagnosticRow("Version",connected?p.getString("remoteVersion","Unknown"):checked,(connected&&p.getString("remoteVersion","").length()>0)?"\u2713":"?","Child app"));
        TextView permissionsTitle=tv("Permissions",16);permissionsTitle.setTypeface(android.graphics.Typeface.DEFAULT_BOLD);root.addView(permissionsTitle);
        remotePermissionRows(p,connected,checked);
        root.addView(diagnosticRow("DND access",connected?p.getString("remoteDnd","Unknown"):checked,(connected&&p.getString("remoteDnd","").length()>0)?"\u2713":"?","Ping during DND"));
        Button refresh=menuButton("troubleshooting");refresh.setText("Refresh diagnostics");Button logs=menuButton("logs");logs.setText("Open logs");Button export=menuButton("logs");export.setText("Export logs");root.addView(refresh);root.addView(logs);root.addView(export);
        refresh.setOnClickListener(v->{cmdWithCallback("usage","today",resp->{updateUsageViews(resp,tv("",1),null);rememberUsageRows(resp);refreshRemoteLockState(resp);addLog("Connection","Info","Diagnostics refreshed",resp);showTroubleshootingScreen();},err->{requestChildDiscovery();addLog("Connection","Error","Diagnostics refresh failed",err);out(err);showTroubleshootingScreen();});});
        logs.setOnClickListener(v->showLogsScreen());export.setOnClickListener(v->{String data=getSharedPreferences("p",0).getString("logs","");Intent send=new Intent(Intent.ACTION_SEND);send.setType("text/plain");send.putExtra(Intent.EXTRA_SUBJECT,"Parental-Link logs");send.putExtra(Intent.EXTRA_TEXT,data.length()>0?data:"No logs");startActivity(Intent.createChooser(send,"Export logs"));});
    }
    View diagnosticRow(String label,String value,String state,String detail){boolean bad="X".equals(state);boolean unknown="?".equals(state);LinearLayout box=new LinearLayout(this);box.setOrientation(LinearLayout.VERTICAL);box.setBackgroundColor(UiFactory.bg(this));LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);row.setGravity(Gravity.CENTER_VERTICAL);row.setPadding(UiFactory.dp(this,10),UiFactory.dp(this,8),UiFactory.dp(this,8),UiFactory.dp(this,8));LinearLayout texts=new LinearLayout(this);texts.setOrientation(LinearLayout.VERTICAL);TextView title=tv(label,15);title.setTypeface(android.graphics.Typeface.DEFAULT_BOLD);title.setSingleLine(false);TextView sub=UiFactory.mutedText(this,(value==null?"":value)+(detail!=null&&detail.length()>0?" - "+detail:""),13);sub.setSingleLine(false);sub.setMaxLines(2);sub.setEllipsize(TextUtils.TruncateAt.END);texts.addView(title,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,ViewGroup.LayoutParams.WRAP_CONTENT));texts.addView(sub,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,ViewGroup.LayoutParams.WRAP_CONTENT));row.addView(texts,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));TextView icon=tv(bad?"Fix":(unknown?"Check":"OK"),12);icon.setGravity(Gravity.CENTER);icon.setTypeface(android.graphics.Typeface.DEFAULT_BOLD);icon.setTextColor(Color.WHITE);icon.setIncludeFontPadding(false);icon.setPadding(UiFactory.dp(this,8),0,UiFactory.dp(this,8),0);android.graphics.drawable.GradientDrawable bg=new android.graphics.drawable.GradientDrawable();bg.setColor(bad?UiFactory.red():(unknown?Color.rgb(120,130,145):UiFactory.green()));bg.setCornerRadius(UiFactory.dp(this,999));icon.setBackground(bg);LinearLayout.LayoutParams ilp=new LinearLayout.LayoutParams(ViewGroup.LayoutParams.WRAP_CONTENT,UiFactory.dp(this,26));ilp.setMargins(UiFactory.dp(this,8),0,0,0);row.addView(icon,ilp);box.addView(row,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,ViewGroup.LayoutParams.WRAP_CONTENT));View divider=new View(this);divider.setBackgroundColor(UiFactory.border(this));box.addView(divider,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,1));box.setLayoutParams(new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,ViewGroup.LayoutParams.WRAP_CONTENT));return box;}
    View statusRow(String label,boolean ok,String detail){return diagnosticRow(label,detail,ok?"\u2713":"X","");}
