    void remotePermissionRows(SharedPreferences p,boolean connected,String checked){String raw=p.getString("remotePermissions","");PermissionReport report=PermissionReport.parse(raw);if(!connected||raw.trim().length()==0){root.addView(diagnosticRow("Device admin",checked,"?","Screen lock"));root.addView(diagnosticRow("App usage access",checked,"?","Current app, most used apps"));root.addView(diagnosticRow("Accessibility",checked,"?","Blocking apps"));root.addView(diagnosticRow("Notifications",checked,"?","Alerts"));root.addView(diagnosticRow("Camera",checked,"?","QR pairing and future visual checks"));root.addView(diagnosticRow("Microphone",checked,"?","Chat audio and future voice checks"));root.addView(diagnosticRow("Draw over apps",checked,"?","Prompts"));root.addView(diagnosticRow("Battery unrestricted",checked,"?","Background service"));return;}for(Map.Entry<String,Boolean> e:report.values.entrySet()){String label=permissionLabel(e.getKey());boolean ok=Boolean.TRUE.equals(e.getValue());root.addView(diagnosticRow(label,ok?"Enabled":"Needed",ok?"\u2713":"X",permissionHelp(e.getKey())));}}
    String permissionLabel(String key){if("admin".equals(key))return "Device admin";if("usage".equals(key))return "App usage access";if("accessibility".equals(key))return "Accessibility";if("notifications".equals(key))return "Notifications";if("camera".equals(key))return "Camera";if("microphone".equals(key))return "Microphone";if("overlay".equals(key))return "Draw over apps";if("dndPolicy".equals(key))return "Do Not Disturb access";if("battery".equals(key))return "Battery unrestricted";return key;}
    String permissionHelp(String key){if("admin".equals(key))return "Screen lock";if("usage".equals(key))return "Current app, most used apps";if("accessibility".equals(key))return "Blocking apps";if("notifications".equals(key))return "Alerts";if("camera".equals(key))return "QR pairing and future visual checks";if("microphone".equals(key))return "Chat audio and future voice checks";if("overlay".equals(key))return "Prompts";if("dndPolicy".equals(key))return "Ping during DND";if("battery".equals(key))return "Background service";return "";}
    void showVersionScreen(){showSettingsScreen();}
    boolean childLocalPermissionsOk(){return isDeviceAdminActive()&&hasUsageAccess()&&isAccessibilityEnabled()&&hasNotificationPermission()&&hasCameraPermission()&&hasMicrophonePermission()&&hasOverlayPermission()&&hasNotificationPolicyAccess()&&isBatteryUnrestricted();}
    boolean hasNotificationPermission(){try{return Build.VERSION.SDK_INT<33||checkSelfPermission(Manifest.permission.POST_NOTIFICATIONS)==PackageManager.PERMISSION_GRANTED;}catch(Exception e){return false;}}
    boolean hasCameraPermission(){try{return Build.VERSION.SDK_INT<23||checkSelfPermission(Manifest.permission.CAMERA)==PackageManager.PERMISSION_GRANTED;}catch(Exception e){return false;}}
    boolean hasMicrophonePermission(){try{return Build.VERSION.SDK_INT<23||checkSelfPermission(Manifest.permission.RECORD_AUDIO)==PackageManager.PERMISSION_GRANTED;}catch(Exception e){return false;}}
    boolean hasNotificationPolicyAccess(){try{NotificationManager nm=(NotificationManager)getSystemService(NOTIFICATION_SERVICE);return nm!=null&&nm.isNotificationPolicyAccessGranted();}catch(Exception e){return false;}}
    boolean hasOverlayPermission(){try{if(Build.VERSION.SDK_INT<23)return true;if(Settings.canDrawOverlays(this))return true;AppOpsManager a=(AppOpsManager)getSystemService(APP_OPS_SERVICE);if(a!=null){int mode=a.checkOpNoThrow(AppOpsManager.OPSTR_SYSTEM_ALERT_WINDOW,android.os.Process.myUid(),getPackageName());return mode==AppOpsManager.MODE_ALLOWED;}}catch(Exception ignored){}return false;}
    boolean isBatteryUnrestricted(){try{PowerManager pm=(PowerManager)getSystemService(POWER_SERVICE);return pm!=null&&pm.isIgnoringBatteryOptimizations(getPackageName());}catch(Exception e){return false;}}
    void openOverlayPermissionSettings(){Intent i=new Intent(Settings.ACTION_MANAGE_OVERLAY_PERMISSION,Uri.parse("package:"+getPackageName()));try{startActivity(i);}catch(Exception e){try{startActivity(new Intent(Settings.ACTION_MANAGE_OVERLAY_PERMISSION));}catch(Exception ignored){startActivity(new Intent(Settings.ACTION_SETTINGS));}}}
    void openBatteryPermissionSettings(){try{if(Build.VERSION.SDK_INT>=23&&!isBatteryUnrestricted()){Intent i=new Intent(Settings.ACTION_REQUEST_IGNORE_BATTERY_OPTIMIZATIONS,Uri.parse("package:"+getPackageName()));startActivity(i);return;}}catch(Exception ignored){}try{startActivity(new Intent(Settings.ACTION_IGNORE_BATTERY_OPTIMIZATION_SETTINGS));}catch(Exception e){startActivity(new Intent(Settings.ACTION_SETTINGS));}}
    String childLocalPermissionSummary(){return "admin="+isDeviceAdminActive()+", usage="+hasUsageAccess()+", accessibility="+isAccessibilityEnabled()+", notifications="+hasNotificationPermission()+", camera="+hasCameraPermission()+", microphone="+hasMicrophonePermission()+", overlay="+hasOverlayPermission()+", dndPolicy="+hasNotificationPolicyAccess()+", battery="+isBatteryUnrestricted();}

    void showChildSettingsGate(){base("Unlock settings");currentScreen="child_settings_gate";SharedPreferences p=getSharedPreferences("p",0);root.addView(tv("Enter a one-time code from the parent app or the child master password.",15));EditText code=oneLine("Code or master password");code.setInputType(InputType.TYPE_CLASS_NUMBER|InputType.TYPE_NUMBER_VARIATION_PASSWORD);code.setFilters(new InputFilter[]{new InputFilter.LengthFilter(8)});root.addView(code);addLargeUnlockPad(code,8);Button unlock=btn("Unlock settings");Button back=btn("Back to dashboard");root.addView(unlock);root.addView(back);unlock.setOnClickListener(v->{String entered=code.getText().toString().trim();String master=p.getString("parentPassword","");String otp=p.getString("childOtp","");if(entered.length()==0){toast("Enter a code");return;}if(otp.length()>0&&entered.equals(otp)){p.edit().remove("childOtp").remove("childOtpParent").apply();showChildSettings("one-time code");return;}if(master.length()>0&&entered.equals(master)){showChildSettings("master password");return;}addLog("Wrong child settings unlock attempt");toast("Wrong code");});back.setOnClickListener(v->showChild());}

    void startQrScanSafely(){try{if(Build.VERSION.SDK_INT>=23&&checkSelfPermission(Manifest.permission.CAMERA)!=PackageManager.PERMISSION_GRANTED){requestPermissions(new String[]{Manifest.permission.CAMERA},CAMERA_SCAN_REQUEST);toast("Allow camera permission, then press Scan QR again");return;}IntentIntegrator integrator=new IntentIntegrator(this);integrator.setPrompt("Scan child pairing QR");integrator.setBeepEnabled(false);integrator.setOrientationLocked(false);integrator.initiateScan();}catch(Exception e){toast("QR scanner unavailable. Enter the pairing code manually.");addLog("QR scan failed: "+e.getClass().getSimpleName());}}

    void showChildSettings(String method){base(tr(R.string.child_settings));currentScreen="child_settings";root.addView(tv(tr(R.string.unlocked_with)+": "+method,14));root.addView(tv(tr(R.string.connection_information),18));root.addView(tv("Parent: "+getSharedPreferences("p",0).getString("parentName","Parent Control")+"\nDevice ID: "+getSharedPreferences("p",0).getString("localDeviceId","unknown")+"\nIP: "+getIp()+"\nServer: running",14));root.addView(tv(childLocalPermissionsOk()?"OK - "+tr(R.string.required_access_ok):"Review - "+tr(R.string.new_permissions_needed),16));root.addView(tv(tr(R.string.required_access),18));addPermissionRow(tr(R.string.device_administrator),isDeviceAdminActive(),v->startActivity(new Intent(DevicePolicyManager.ACTION_ADD_DEVICE_ADMIN).putExtra(DevicePolicyManager.EXTRA_DEVICE_ADMIN,new ComponentName(this,AdminReceiver.class))));addPermissionRow(tr(R.string.usage_access),hasUsageAccess(),v->startActivity(new Intent(Settings.ACTION_USAGE_ACCESS_SETTINGS)));addPermissionRow(tr(R.string.accessibility_service),isAccessibilityEnabled(),v->startActivity(new Intent(Settings.ACTION_ACCESSIBILITY_SETTINGS)));addPermissionRow(tr(R.string.notifications),hasNotificationPermission(),v->{if(Build.VERSION.SDK_INT>=33)requestPermissions(new String[]{Manifest.permission.POST_NOTIFICATIONS},7);else toast("Notifications are already allowed on this Android version");});addPermissionRow("Camera",hasCameraPermission(),v->{if(Build.VERSION.SDK_INT>=23)requestPermissions(new String[]{Manifest.permission.CAMERA},8);else toast("Camera is already allowed on this Android version");});addPermissionRow("Microphone",hasMicrophonePermission(),v->{if(Build.VERSION.SDK_INT>=23)requestPermissions(new String[]{Manifest.permission.RECORD_AUDIO},9);else toast("Microphone is already allowed on this Android version");});addPermissionRow(tr(R.string.display_over_other_apps),hasOverlayPermission(),v->openOverlayPermissionSettings());addPermissionRow(tr(R.string.dnd_policy_access),hasNotificationPolicyAccess(),v->startActivity(new Intent(Settings.ACTION_NOTIFICATION_POLICY_ACCESS_SETTINGS)));addPermissionRow(tr(R.string.battery_unrestricted),isBatteryUnrestricted(),v->openBatteryPermissionSettings());Button check=btn(tr(R.string.check_again));Button restart=btn(tr(R.string.restart_server));Button travel=btn(tr(R.string.remove_all_limitations_travel));Button remove=btn(tr(R.string.remove_parental_control));root.addView(check);root.addView(restart);root.addView(travel);root.addView(remove);check.setOnClickListener(v->showChildSettings(method));restart.setOnClickListener(v->startChildService());travel.setOnClickListener(v->confirmChildTravelMode(method));remove.setOnClickListener(v->confirmRemoveApp(method));root.addView(log);listenLogs();}
    void addPermissionRow(String name,boolean ok,View.OnClickListener action){LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);TextView t=tv((ok?"OK  ":"Need  ")+name,15);row.addView(t,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));if(!ok){Button b=btn("Enable");b.setOnClickListener(action);row.addView(b);}root.addView(row);}

    void confirmChildTravelMode(String method){new AlertDialog.Builder(this).setTitle(tr(R.string.remove_all_limitations_title)).setMessage(tr(R.string.remove_all_limitations_msg)+"\n\n"+tr(R.string.authorised_by)+": "+method).setNegativeButton("Cancel",null).setPositiveButton(tr(R.string.remove_limitations),(d,w)->{removeAllLocalLimitations(method);showChildSettings(method);}).show();}
    void removeAllLocalLimitations(String method){SharedPreferences prefs=getSharedPreferences("rules",0);SharedPreferences.Editor ed=prefs.edit();for(String k:prefs.getAll().keySet()){if(k.startsWith("blocked_until_"))ed.remove(k);}ed.remove("lock_until").remove("lock_mode").remove("active_profile").remove("profile_until").apply();sendBroadcast(new Intent("com.enigma.familylinklite.CLOSE_ATTENTION"));addLog("Security","Info","Travel mode enabled","All local limitations removed by "+method);toast("All limitations removed");}

    boolean isDeviceAdminActive(){try{DevicePolicyManager dpm=(DevicePolicyManager)getSystemService(DEVICE_POLICY_SERVICE);return dpm!=null&&dpm.isAdminActive(new ComponentName(this,AdminReceiver.class));}catch(Exception e){return false;}}
    boolean hasUsageAccess(){try{AppOpsManager a=(AppOpsManager)getSystemService(APP_OPS_SERVICE);int mode=a.checkOpNoThrow(AppOpsManager.OPSTR_GET_USAGE_STATS,android.os.Process.myUid(),getPackageName());return mode==AppOpsManager.MODE_ALLOWED;}catch(Exception e){return false;}}
    boolean isAccessibilityEnabled(){try{String enabled=Settings.Secure.getString(getContentResolver(),Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES);return enabled!=null&&enabled.toLowerCase(Locale.US).contains(getPackageName().toLowerCase(Locale.US));}catch(Exception e){return false;}}
    void confirmRemoveApp(String method){new AlertDialog.Builder(this).setTitle(tr(R.string.remove_settings_title)).setMessage(tr(R.string.remove_settings_msg)+"\n\n"+tr(R.string.authorised_by)+": "+method).setNegativeButton("Cancel",null).setPositiveButton(tr(R.string.request_removal),(d,w)->{requestChildRemoval(method);}).show();}

    void requestChildRemoval(String method){SharedPreferences p=getSharedPreferences("p",0);p.edit().putBoolean("childRemovalRequested",true).putString("childRemovalMethod",method).putLong("childRemovalRequestedAt",System.currentTimeMillis()).apply();addLog("Security","Warning","Child requested removal of Parental-Link settings","Authorised by: "+method);showChildRemovalPending(method);}

    void showChildRemovalPending(String method){base(tr(R.string.removal_requested));currentScreen="child_removal_pending";root.addView(tv(tr(R.string.parent_informed_next_connection),16));root.addView(tv(tr(R.string.authorised_by)+": "+method,14));root.addView(tv("Keep this tablet on the same Wi-Fi until the parent confirms removal. If the parent is not available, you can remove local settings manually below.",14));Button check=btn(tr(R.string.check_again));Button force=btn(tr(R.string.remove_local_settings_now));Button back=btn(tr(R.string.back));root.addView(check);root.addView(force);root.addView(back);check.setOnClickListener(v->showChildRemovalPending(method));force.setOnClickListener(v->{clearChildParentalLinkSettings();toast(tr(R.string.settings_removed_locally));showStart();});back.setOnClickListener(v->showChild());}

    void clearChildParentalLinkSettings(){try{getSharedPreferences("rules",0).edit().clear().apply();}catch(Exception ignored){}SharedPreferences p=getSharedPreferences("p",0);String id=p.getString("localDeviceId",UUID.randomUUID().toString());p.edit().clear().putString("localDeviceId",id).apply();}
    void showSettingsScreen(){base("Settings");currentScreen="settings";root.addView(sectionLabel("Theme"));root.addView(themeModeRow());root.addView(sectionLabel("Application Language"));root.addView(languageOptions(false));root.addView(sectionLabel("Dashboard actions"));root.addView(settingsRow("Quick action slot 1",slotDescription(1)+" - tap to change",v->chooseQuickSlot(1)));root.addView(menuDivider());root.addView(settingsRow("Quick action slot 2",slotDescription(2)+" - tap to change",v->chooseQuickSlot(2)));root.addView(sectionLabel("Parent app lock"));root.addView(parentBiometricUnlockRow());root.addView(sectionLabel("Parent monitor"));root.addView(parentPermanentNotificationRow());root.addView(sectionLabel("Version & updates"));SharedPreferences p=getSharedPreferences("p",0);String latest=p.getString("latestVersion","");TextView version=UiFactory.mutedText(this,"Current: "+APP_VERSION+(latest.length()>0?"  Latest: "+latest:""),13);root.addView(version);Button update=menuButton("updates");boolean updateReady=latest.length()>0&&!latest.equals(APP_VERSION);update.setText(updateReady?"Open latest release":"Up-to-date - check again");root.addView(update);update.setOnClickListener(v->{String url=getSharedPreferences("p",0).getString("latestReleaseUrl","");if(updateReady&&url.length()>0)startActivity(new Intent(Intent.ACTION_VIEW,Uri.parse(url)));else checkLatestRelease(DEFAULT_REPO,version);});root.addView(sectionLabel("Delete Settings"));TextView remove=settingsRow("!  "+tr(R.string.remove_parental_control),"Delete local Parental-Link settings",v->confirmRemoveParentalControl());remove.setTextColor(UiFactory.textColor(this));root.addView(remove);}
    CheckBox parentBiometricUnlockRow(){SharedPreferences p=getSharedPreferences("p",0);CheckBox box=new CheckBox(this);box.setText(canUseDeviceCredential()?"Unlock with biometrics/device credential\nMaster password remains the fallback":"Unlock with biometrics unavailable\nSet a secure screen lock on this phone first");box.setTextColor(UiFactory.textColor(this));box.setTextSize(15);box.setChecked(canUseDeviceCredential()&&p.getBoolean("parentBiometricUnlock",false));box.setEnabled(canUseDeviceCredential());box.setPadding(UiFactory.dp(this,8),UiFactory.dp(this,4),UiFactory.dp(this,8),UiFactory.dp(this,4));box.setOnCheckedChangeListener((button,checked)->{if(checked){p.edit().putBoolean("parentBiometricUnlock",true).putBoolean("parentLockConfigured",true).apply();return;}if(p.getBoolean("parentBiometricUnlock",false)){button.setChecked(true);pendingSecureAction="disable_parent_biometric";authPromptLaunched=false;showParentAppLock();}else p.edit().putBoolean("parentBiometricUnlock",false).putBoolean("parentLockConfigured",true).apply();});return box;}
    CheckBox parentPermanentNotificationRow(){SharedPreferences p=getSharedPreferences("p",0);CheckBox box=new CheckBox(this);box.setText("Permanent parent notification\nKeep parent monitor visible");box.setTextColor(UiFactory.textColor(this));box.setTextSize(15);box.setChecked(p.getBoolean("parentPermanentNotification",false));box.setPadding(UiFactory.dp(this,8),UiFactory.dp(this,4),UiFactory.dp(this,8),UiFactory.dp(this,4));box.setOnCheckedChangeListener((button,checked)->{p.edit().putBoolean("parentPermanentNotification",checked).apply();if(checked)startService(new Intent(this,ParentMonitorService.class));else stopParentMonitorAndExitNotificationOnly();});return box;}
    void stopParentMonitorAndExitNotificationOnly(){try{stopService(new Intent(this,ParentMonitorService.class));}catch(Exception ignored){}try{NotificationManager nm=(NotificationManager)getSystemService(NOTIFICATION_SERVICE);if(nm!=null)nm.cancel(ParentMonitorService.NOTIFICATION_ID);}catch(Exception ignored){}}
    RadioGroup languageOptions(boolean targetChild){RadioGroup group=new RadioGroup(this);group.setOrientation(RadioGroup.VERTICAL);SharedPreferences p=getSharedPreferences("p",0);String current=targetChild?p.getString("childLanguage","system"):LanguageManager.current(this);String[] values={"system","en","el","fr"};for(String val:values){RadioButton rb=new RadioButton(this);rb.setId(View.generateViewId());rb.setText(LanguageManager.label(val));rb.setTextColor(UiFactory.textColor(this));rb.setTag(val);group.addView(rb);if(val.equals(current))group.check(rb.getId());}group.setOnCheckedChangeListener((g,id)->{RadioButton rb=g.findViewById(id);if(rb==null)return;String lang=String.valueOf(rb.getTag());if(targetChild){p.edit().putString("childLanguage",lang).apply();cmd("set_language",lang);}else{LanguageManager.set(this,lang);recreate();}});return group;}
    void confirmRemoveParentalControl(){SharedPreferences p=getSharedPreferences("p",0);String otherParent=p.getString("otherParentName","");String devices=childDeviceListText();StringBuilder msg=new StringBuilder();msg.append("This does not reset the device,\n");msg.append("it only removes the settings of the Parental-Link application on your device.\n\n");if(otherParent.length()>0){msg.append("The Parental-Link application of ").append(otherParent).append(" will continue to supervise the following devices:\n").append(devices);}else{msg.append("The Parental-Link application will delete its settings and a new first-time connection will be available for the following devices:\n").append(devices);}AlertDialog dlg=new AlertDialog.Builder(this).setTitle("Remove supervision?").setMessage(msg.toString()).setNegativeButton("Cancel",null).setPositiveButton("Remove in 5",null).create();dlg.setOnShowListener(di->{Button b=dlg.getButton(AlertDialog.BUTTON_POSITIVE);b.setEnabled(false);final int[] remaining={5};Runnable tick=new Runnable(){public void run(){if(!dlg.isShowing())return;if(remaining[0]>0){b.setText("Remove in "+remaining[0]);remaining[0]--;handler.postDelayed(this,1000);}else{b.setText("Remove");b.setEnabled(true);}}};tick.run();b.setOnClickListener(v->{dlg.dismiss();resetLocalParentalLinkData();});});dlg.show();}

    String childDeviceListText(){SharedPreferences p=getSharedPreferences("p",0);String nickname=p.getString("childNickname","Child device");String ip=p.getString("childIp","");String line="- "+nickname+(ip.length()>0?" ("+ip+")":"");return line+"\n";}

    void resetLocalParentalLinkData(){try{stopService(new Intent(this,ParentMonitorService.class));}catch(Exception ignored){}getSharedPreferences("p",0).edit().clear().apply();unlockedThisRun=false;authPromptLaunched=false;childIp="";key=null;toast("Parental-Link settings removed");showStart();}
    void showUnlockCodesScreen(){base("Unlock codes");currentScreen="unlock_codes";TextView current=tv("Generating...",30);current.setGravity(Gravity.CENTER);root.addView(current);View bar=new View(this);bar.setBackgroundColor(UiFactory.green());root.addView(bar,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,UiFactory.dp(this,8)));Button gen=menuButton("unlock_codes");gen.setText("Generate new code");root.addView(gen);gen.setOnClickListener(v->generateUnlockCode(current,bar));generateUnlockCode(current,bar);root.addView(log);}
    void generateUnlockCode(TextView current,View bar){String who=getSharedPreferences("p",0).getString("parentName","Parent Control");cmdWithCallback("otp_generate",who,resp->{String code=resp.replace("OTP:","").trim();current.setText(code.length()>0?code:"No code returned");addLog("One-time unlock code generated");startCodeTimer(bar,300000L);},err->{current.setText("Failed to generate code");out(err);});}
    void startCodeTimer(View bar,long totalMs){long start=System.currentTimeMillis();int full=Math.max(1,getResources().getDisplayMetrics().widthPixels-UiFactory.dp(this,28));Runnable tick=new Runnable(){public void run(){if(bar.getParent()==null)return;long elapsed=System.currentTimeMillis()-start;float left=Math.max(0f,1f-(float)elapsed/(float)totalMs);int w=Math.max(UiFactory.dp(LegacyMainActivity.this,8),(int)(full*left));ViewGroup.LayoutParams lp=bar.getLayoutParams();lp.width=w;bar.setLayoutParams(lp);bar.setBackgroundColor(left>0.5f?UiFactory.green():(left>0.2f?Color.rgb(245,180,40):UiFactory.red()));if(left>0)handler.postDelayed(this,1000);}};tick.run();}
    void showBlockedAppsScreen(){base(tr(R.string.menu_blocked_apps));currentScreen="blocked_apps";String role=getSharedPreferences("p",0).getString("role","");if("child".equals(role)){root.addView(tv(tr(R.string.apps_blocked_on_this_device),16));LinearLayout list=new LinearLayout(this);list.setOrientation(LinearLayout.VERTICAL);root.addView(list,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,0,1));renderLocalBlockedAppsList(list);Button refresh=btn(tr(R.string.refresh));root.addView(refresh);refresh.setOnClickListener(v->renderLocalBlockedAppsList(list));return;}root.addView(UiFactory.mutedText(this,tr(R.string.blocked_apps_help),14));TextView status=UiFactory.mutedText(this,"Loading child app list...",13);root.addView(status);root.addView(sectionLabel("Current restrictions"));LinearLayout list=new LinearLayout(this);list.setOrientation(LinearLayout.VERTICAL);root.addView(list);root.addView(sectionLabel("Apps on child"));LinearLayout installed=new LinearLayout(this);installed.setOrientation(LinearLayout.VERTICAL);root.addView(installed,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,0,1));Button refresh=btn(tr(R.string.refresh));root.addView(refresh,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,UiFactory.dp(this,48)));refresh.setOnClickListener(v->{getSharedPreferences("p",0).edit().remove("cachedInstalledApps").apply();preloadInstalledApps(status,installed);loadBlockedAppsList(list);});loadBlockedAppsList(list);String cached=getSharedPreferences("p",0).getString("cachedInstalledApps","");if(cached.trim().length()>0){renderInstalledAppsForBlocking(installed,cached);status.setText(BlockedAppEntry.parseInstalledList(cached).size()+" apps loaded from cache");}else preloadInstalledApps(status,installed);}
    void renderInstalledAppsForBlocking(LinearLayout list,String resp){list.removeAllViews();ArrayList<BlockedAppEntry> apps=filterAlreadyBlocked(BlockedAppEntry.parseInstalledList(resp));if(apps.size()==0){list.addView(tv("No more apps available to block",14));return;}int max=Math.min(apps.size(),80);for(int i=0;i<max;i++){BlockedAppEntry e=apps.get(i);LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);row.setGravity(Gravity.CENTER_VERTICAL);TextView name=tv(e.displayName(),13);Button timer=iconTextButton("ic_proto_hourglass","");Button block=btn("Block");row.addView(name,new LinearLayout.LayoutParams(0,UiFactory.dp(this,46),1));row.addView(timer,new LinearLayout.LayoutParams(UiFactory.dp(this,54),UiFactory.dp(this,42)));row.addView(block,new LinearLayout.LayoutParams(UiFactory.dp(this,78),UiFactory.dp(this,42)));list.addView(row);timer.setOnClickListener(v->showAppTimeoutDialog(e.pkg,list));block.setOnClickListener(v->cmdWithCallback("block_app",e.pkg,ok->{toast("Blocked");getSharedPreferences("p",0).edit().remove("cachedInstalledApps").apply();showBlockedAppsScreen();},err->{toast("Block failed");out(err);}));}}
    void showAppTimeoutDialog(String pkg,LinearLayout refreshList){final int[] minutes={Math.max(1,getSharedPreferences("p",0).getInt("lastAppTimeoutMinutes",30))};LinearLayout box=new LinearLayout(this);box.setOrientation(LinearLayout.VERTICAL);TextView value=tv("",30);value.setGravity(Gravity.CENTER);EditText input=oneLine("Minutes");input.setInputType(InputType.TYPE_CLASS_NUMBER);input.setGravity(Gravity.CENTER);LinearLayout quick=new LinearLayout(this);quick.setOrientation(LinearLayout.HORIZONTAL);Button minus10=btn("-10");Button minus5=btn("-5");Button plus5=btn("+5");Button plus10=btn("+10");quick.addView(minus10,new LinearLayout.LayoutParams(0,UiFactory.dp(this,44),1));quick.addView(minus5,new LinearLayout.LayoutParams(0,UiFactory.dp(this,44),1));quick.addView(plus5,new LinearLayout.LayoutParams(0,UiFactory.dp(this,44),1));quick.addView(plus10,new LinearLayout.LayoutParams(0,UiFactory.dp(this,44),1));box.addView(value);box.addView(input);box.addView(quick);Runnable refresh=()->{minutes[0]=Math.max(1,Math.min(240,minutes[0]));value.setText(minutes[0]+" min");input.setText(String.valueOf(minutes[0]));};View.OnClickListener adjust=v->{try{minutes[0]=Integer.parseInt(input.getText().toString().trim());}catch(Exception ignored){}if(v==minus10)minutes[0]-=10;else if(v==minus5)minutes[0]-=5;else if(v==plus5)minutes[0]+=5;else if(v==plus10)minutes[0]+=10;refresh.run();};minus10.setOnClickListener(adjust);minus5.setOnClickListener(adjust);plus5.setOnClickListener(adjust);plus10.setOnClickListener(adjust);refresh.run();new AlertDialog.Builder(this).setTitle("Block app for").setView(box).setNegativeButton("Cancel",null).setPositiveButton("Start",(d,w)->{try{minutes[0]=Integer.parseInt(input.getText().toString().trim());}catch(Exception ignored){}minutes[0]=Math.max(1,Math.min(240,minutes[0]));getSharedPreferences("p",0).edit().putInt("lastAppTimeoutMinutes",minutes[0]).apply();cmdWithCallback("block_app",pkg+"|"+minutes[0],ok->{toast("Timed block set");showBlockedAppsScreen();},err->{toast("Timed block failed");out(err);});}).show();}

    void renderLocalBlockedAppsList(LinearLayout list){list.removeAllViews();Map<String,?> all=getSharedPreferences("rules",0).getAll();long now=System.currentTimeMillis();int count=0;for(String k:all.keySet()){if(!k.startsWith("blocked_until_"))continue;long until=0;try{until=((Number)all.get(k)).longValue();}catch(Exception ignored){}if(until<=now)continue;String pkg=k.substring("blocked_until_".length());LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);TextView name=tv(friendlyAppName(pkg)+"\nuntil "+new java.text.SimpleDateFormat("HH:mm",java.util.Locale.US).format(new java.util.Date(until)),14);Button remove=btn(tr(R.string.remove));row.addView(name,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));row.addView(remove);list.addView(row);remove.setOnClickListener(v->{getSharedPreferences("rules",0).edit().remove("blocked_until_"+pkg).apply();addLog("Activity","Info","Blocked app removed locally",friendlyAppName(pkg));renderLocalBlockedAppsList(list);});count++;}if(count==0)list.addView(tv(tr(R.string.no_blocked_apps),15));}

