    void updateUsageViews(String resp,TextView screen,TextView apps){long total=0;boolean explicitTotal=false;String[] lines=resp.split("\\n");StringBuilder top=new StringBuilder("Most active apps:\n");int n=0;SharedPreferences.Editor ed=getSharedPreferences("p",0).edit();for(String line:lines){if(line.startsWith("VERSION:")){ed.putString("remoteVersion",line.substring(8).trim());continue;}if(line.startsWith("PROTOCOL:")){ed.putString("remoteProtocol",line.substring(9).trim());continue;}if(line.startsWith("CAPABILITIES:")){ed.putString("remoteCapabilities",line.substring(13).trim());continue;}if(line.startsWith("PERMISSIONS:")){ed.putString("remotePermissions",line.substring(12).trim());continue;}if(line.startsWith("DND:")){ed.putString("remoteDnd",line.substring(4).trim());continue;}if(line.startsWith("BATTERY:")){try{ed.putInt("remoteBattery",Integer.parseInt(line.substring(8).trim()));}catch(Exception ignored){}continue;}if(line.startsWith("CHARGING:")){ed.putBoolean("remoteCharging",Boolean.parseBoolean(line.substring(9).trim()));continue;}if(line.startsWith("WIFI_BARS:")){try{ed.putInt("remoteWifiBars",Integer.parseInt(line.substring(10).trim()));}catch(Exception ignored){}continue;}if(line.startsWith("CURRENT_APP:")){String app=line.substring(12).trim();ed.putString("lastCurrentApp",app).putString("lastCurrentPackage",currentAppPackage(app));continue;}if(line.startsWith("USAGE_TOTAL_MINUTES:")){try{total=Long.parseLong(line.substring(20).trim());explicitTotal=true;}catch(Exception ignored){}continue;}if(line.startsWith("CHILD_LANGUAGE:")){ed.putString("childLanguage",line.substring(15).trim());continue;}if(line.startsWith("CHILD_REMOVAL_REQUESTED:")){String val=line.substring(24).trim();ed.putBoolean("childRemovalRequested",Boolean.parseBoolean(val));continue;}if(line.startsWith("ASK_PARENT_REQUESTED:")){String val=line.substring(21).trim();ed.putBoolean("childUnlockRequestPending",Boolean.parseBoolean(val));continue;}if(line.startsWith("CHILD_REMOVAL_METHOD:")){ed.putString("childRemovalMethod",line.substring(21).trim());continue;}if(line.startsWith("ASK_PARENT_REASON:")){ed.putString("childUnlockRequestReason",line.substring(18).trim());continue;}if(line.startsWith("ASK_PARENT_AT:")){try{ed.putLong("childUnlockRequestAt",Long.parseLong(line.substring(14).trim()));}catch(Exception ignored){}continue;}if(line.startsWith("ASK_PARENT_SNOOZE_UNTIL:")){try{ed.putLong("childUnlockSnoozeUntil",Long.parseLong(line.substring(24).trim()));}catch(Exception ignored){}continue;}if(!line.contains(": ")||!line.endsWith(" min"))continue;try{long mins=Long.parseLong(line.substring(line.indexOf(": ")+2,line.indexOf(" min")).trim());if(!explicitTotal)total+=mins;if(n<3){top.append(n+1).append(". ").append(line).append("\n");n++;}}catch(Exception ignored){}}liveStatusThisRun=true;ed.putLong("lastStatusMs",System.currentTimeMillis()).putLong("todayMinutes",total).putBoolean("childDeviceRemoved",false).putBoolean("pairingMismatch",false).remove("pairingMismatchMessage").apply();if(getSharedPreferences("p",0).getBoolean("childRemovalRequested",false)){getSharedPreferences("p",0).edit().putBoolean("childRemovalPending",true).apply();String m=getSharedPreferences("p",0).getString("childRemovalMethod","child request");addLog("Security","Warning","Child requested supervision removal","Authorised by: "+m);tryRemoveChildDeviceOnline();return;}if(getSharedPreferences("p",0).getBoolean("childUnlockRequestPending",false)){SharedPreferences pp=getSharedPreferences("p",0);String reason=pp.getString("childUnlockRequestReason","limitation");long askAt=pp.getLong("childUnlockRequestAt",System.currentTimeMillis());long alertedAt=pp.getLong("lastParentUnlockAlertAt",0);if(askAt<=0)askAt=System.currentTimeMillis();if(askAt!=alertedAt){pp.edit().putLong("lastParentUnlockAlertAt",askAt).apply();addLog("Security","Warning","Child asked parent to unlock",reason);showParentAlertNotification("Unlock request",reason);}}screen.setText(String.format(Locale.US,"Today\n%02d:%02d",total/60,total%60));if(apps!=null){while(n<3){top.append(n+1).append(". --\n");n++;}apps.setText(top.toString());}}

    void startDiscoveryListener(){if(discoveryListenThread!=null&&discoveryListenThread.isAlive())return;discoveryListenThread=new Thread(()->{try{DatagramSocket ds=new DatagramSocket(null);ds.setReuseAddress(true);ds.bind(new InetSocketAddress(DISCOVERY_PORT));byte[] buf=new byte[512];while(true){DatagramPacket p=new DatagramPacket(buf,buf.length);ds.receive(p);String msg=new String(p.getData(),0,p.getLength(),StandardCharsets.UTF_8);String[] parts=msg.split("\\|",-1);if(parts.length>=4&&parts[0].equals("FLITE")){String ip=p.getAddress().getHostAddress();String name=parts.length>4?parts[4]:"Child device";String version=parts.length>5?parts[5]:"";boolean known=false;try{known=key!=null&&parts[3].equals(pairingId());}catch(Exception ignored){}if(known){if(!ip.equals(childIp)){childIp=ip;new SavedConnection(this).saveChildIp(childIp);addLog("Connection","Info","Child rediscovered","New IP: "+childIp);runOnUiThread(()->{toast("Child rediscovered at "+childIp);if("dashboard".equals(currentScreen))prototypeRefresh(true);});}}else if("pair_parent".equals(currentScreen)){SharedPreferences prefs=getSharedPreferences("p",0);String last=prefs.getString("lastPairBroadcastIp","");if(!ip.equals(last)){rememberPairBroadcast(ip,name,version);childIp=ip;runOnUiThread(()->{toast("Child broadcast found at "+ip);showParentConnection(getSharedPreferences("p",0).getString("pendingPairCode",""),ip);});}}}}}catch(Exception ignored){}} ,"Parental-LinkParentDiscovery");discoveryListenThread.start();}
    void requestChildDiscovery(){try{String payload=key==null?"FLITE_PAIR_FIND|"+getSharedPreferences("p",0).getString("localDeviceId",""):"FLITE_FIND|"+pairingId()+"|"+getSharedPreferences("p",0).getString("localDeviceId","");byte[] data=payload.getBytes(StandardCharsets.UTF_8);new Thread(()->{try{DatagramSocket ds=new DatagramSocket();ds.setBroadcast(true);DatagramPacket p=new DatagramPacket(data,data.length,InetAddress.getByName("255.255.255.255"),DISCOVERY_PORT);ds.send(p);ds.close();}catch(Exception e){addLog("Connection","Warning","Discovery request failed",e.getMessage());}},"Parental-LinkFindChild").start();}catch(Exception ignored){}}
    void rememberPairBroadcast(String ip,String name,String version){SharedPreferences prefs=getSharedPreferences("p",0);String found=prefs.getString("pairBroadcasts","");java.util.LinkedHashMap<String,String> items=new java.util.LinkedHashMap<>();String label=(name==null||name.trim().length()==0?"Child device":name.trim().replace("|"," "))+"|"+(version==null?"":version.trim().replace("|"," "));items.put(ip,label);for(String row:found.split("\\n")){String clean=row.trim();if(clean.length()==0)continue;String[] parts=clean.split("\\|",-1);String oldIp=parts.length>0?parts[0].trim():"";if(oldIp.length()==0||oldIp.equals(ip))continue;String oldName=parts.length>1?parts[1]:"Child device";String oldVersion=parts.length>2?parts[2]:"";items.put(oldIp,oldName+"|"+oldVersion);if(items.size()>=5)break;}StringBuilder sb=new StringBuilder();for(Map.Entry<String,String> item:items.entrySet())sb.append(item.getKey()).append("|").append(item.getValue()).append("\n");prefs.edit().putString("pairBroadcasts",sb.toString().trim()).putString("lastPairBroadcastIp",ip).apply();}
    void searchForChildOnNetwork(String reason,boolean redraw){loadLatestSavedChild();SharedPreferences p=getSharedPreferences("p",0);if(p.getBoolean("connectionSearchActive",false)){long started=p.getLong("connectionSearchStartedAt",0);if(started>0&&System.currentTimeMillis()-started<45000L)return;clearConnectionSearch();}addLog("Connection","Info","Broadcast search started",reason);markConnectionSearch("broadcast",redraw);requestChildDiscovery();new Thread(()->{try{Thread.sleep(1800);}catch(Exception ignored){}if(!getSharedPreferences("p",0).getBoolean("connectionSearchActive",false))return;scanLocalNetworkForChild(reason,redraw);},"Parental-LinkScanDelay").start();}
    void markConnectionSearch(String status,boolean redraw){getSharedPreferences("p",0).edit().putBoolean("connectionSearchActive",true).putLong("connectionSearchStartedAt",System.currentTimeMillis()).putString("connectionSearchStatus",status).apply();if("dashboard".equals(currentScreen))showJavaDashboardPrototype();}
    void clearConnectionSearch(){getSharedPreferences("p",0).edit().putBoolean("connectionSearchActive",false).remove("connectionSearchStartedAt").remove("connectionSearchStatus").apply();}
    void scanLocalNetworkForChild(String reason,boolean redraw){new Thread(()->{try{loadLatestSavedChild();String own=getIp();String prefix=subnetPrefix(own);if(prefix.length()==0||key==null){clearConnectionSearch();return;}getSharedPreferences("p",0).edit().putString("connectionSearchStatus","scanning 0%").apply();runOnUiThread(()->{if("dashboard".equals(currentScreen))showJavaDashboardPrototype();});addLog("Connection","Info","Searching local network",reason+" on "+prefix+"0/24");String self=own==null?"":own.trim();int lastPct=-1;int lastActivityPct=-25;for(int i=1;i<=254;i++){int pct=Math.min(100,Math.max(1,(int)Math.round(i*100.0/254.0)));if(pct>=lastPct+10||pct==100){lastPct=pct;getSharedPreferences("p",0).edit().putString("connectionSearchStatus","scanning "+pct+"%").apply();runOnUiThread(()->{if("dashboard".equals(currentScreen))showJavaDashboardPrototype();});}if(pct>=lastActivityPct+25||pct==100){lastActivityPct=pct;addLog("Connection","Info","Network scan "+pct+"%","Encrypted search on "+prefix+"0/24");}String ip=prefix+i;if(ip.equals(self))continue;String resp=tryEncryptedHello(ip);if(resp!=null&&resp.contains("VERSION:")){childIp=ip;new SavedConnection(this).saveChildIp(ip);clearConnectionSearch();updateStatusFromHello(resp);addLog("Connection","Info","Child found on network","New IP: "+ip);runOnUiThread(()->{toast("Child found at "+ip);if("dashboard".equals(currentScreen))showJavaDashboardPrototype();});return;}}clearConnectionSearch();addLog("Connection","Warning","Network search found no child",reason);}catch(Exception e){clearConnectionSearch();addLog("Connection","Warning","Network search failed",e.getMessage());}runOnUiThread(()->{if("dashboard".equals(currentScreen))showJavaDashboardPrototype();});},"Parental-LinkNetworkScan").start();}
    String subnetPrefix(String ip){try{if(ip==null)return "";String[] parts=ip.trim().split("\\.");if(parts.length!=4)return "";return parts[0]+"."+parts[1]+"."+parts[2]+".";}catch(Exception e){return "";}}
    String tryEncryptedHello(String ip){Socket socket=null;try{SavedConnection c=new SavedConnection(this);JSONObject packet=CommandPacket.create("hello","",c.parentName(),c.localDeviceId());socket=new Socket();socket.connect(new InetSocketAddress(ip,PORT),260);socket.setSoTimeout(700);PrintWriter writer=new PrintWriter(socket.getOutputStream(),true);writer.println(CommandClient.encrypt(packet.toString(),key));BufferedReader reader=new BufferedReader(new InputStreamReader(socket.getInputStream()));String encrypted=reader.readLine();if(encrypted==null||encrypted.trim().length()==0)return null;return CommandClient.decrypt(encrypted,key);}catch(Exception ignored){return null;}finally{try{if(socket!=null)socket.close();}catch(Exception ignored){}}}
    String pairingId(){return CryptoUtils.pairingId(key);}
    interface Ok{void call(String s);} interface Err{void call(String s);} void cmd(String type,String value){cmdWithCallback(type,value,resp->{out(resp);},err->{out(err);});}
    void recordCommandStatus(String id,String command,String status,String details,String value){SharedPreferences p=getSharedPreferences("p",0);String safe=(details==null?"":details.replace("\n"," ").replace("|","/"));String safeValue=(value==null?"":value.replace("\n"," ").replace("|","/"));String line=System.currentTimeMillis()+"|"+id+"|"+command+"|"+status+"|"+safe+"|"+safeValue;String hist=p.getString("commandHistory","");String[] old=hist.length()==0?new String[0]:hist.split("\n");StringBuilder next=new StringBuilder(line);int kept=0;for(String row:old){if(row.trim().length()==0)continue;String[] parts=row.split("\\|",-1);if(parts.length>1&&parts[1].equals(id))continue;if(kept++>=24)break;next.append("\n").append(row);}p.edit().putString("lastCommandStatus",prettyCommandName(command)+": "+status).putString("commandHistory",next.toString()).putString("commandLifecycleHistory",next.toString()).apply();}
    void cmdWithCallback(String type,String value,Ok ok,Err err){String commandLabel=type==null?"command":type;String commandId=java.util.UUID.randomUUID().toString();String commandValue=value==null?"":value;boolean quiet=commandLabel.equals("usage")||commandLabel.equals("blocked_apps")||commandLabel.equals("list_apps")||commandLabel.equals("hello")||commandLabel.equals("chat_status");if(!quiet){out("Sending: "+commandLabel);recordCommandStatus(commandId,commandLabel,"Sending",commandValue,commandValue);}new CommandClient(this).send(childIp,key,type,value,resp->{if(!quiet){out("Delivered: "+commandLabel);recordCommandStatus(commandId,commandLabel,"Delivered",resp,commandValue);}if("disable_use".equals(commandLabel))setLocalLockState(true);if("enable_use".equals(commandLabel)){setLocalLockState(false);setLocalTimeoutState(false);}if("lock_timeout".equals(commandLabel))setLocalTimeoutState(true);if("stop_timeout".equals(commandLabel))setLocalTimeoutState(false);if("remove_all_limitations".equals(commandLabel)){setLocalLockState(false);setLocalTimeoutState(false);}ok.call(resp);},e->{String low=e==null?"":e.toLowerCase(java.util.Locale.US);if(low.contains("handshake")||low.contains("decrypt")||low.contains("auth")||low.contains("bad tag")||low.contains("pairing mismatch")){String message=e==null?"Pairing mismatch":e;getSharedPreferences("p",0).edit().putBoolean("pairingMismatch",true).putString("pairingMismatchReason",message).putString("pairingMismatchMessage",message).putLong("pairingMismatchAt",System.currentTimeMillis()).apply();addLog("Security","Warning","Pairing mismatch detected",message);}if(!quiet){out("Failed: "+commandLabel);recordCommandStatus(commandId,commandLabel,"Failed",e,commandValue);}err.call(e);});}


    String currentPairCode(byte[] k){return CryptoUtils.currentPairCode(k,pairCodeEpochMs());}
    long pairCodeEpochMs(){SharedPreferences p=getSharedPreferences("p",0);long epoch=p.getLong("pairCodeEpochMs",0);if(epoch<=0){epoch=System.currentTimeMillis();p.edit().putLong("pairCodeEpochMs",epoch).apply();}return epoch;}
    byte[] getOrCreateKey(){SharedPreferences p=getSharedPreferences("p",0);String saved=p.getString("key",null);if(saved!=null){pairCodeEpochMs();return Base64.getDecoder().decode(saved);}byte[] b=new byte[32];new SecureRandom().nextBytes(b);p.edit().putString("key",Base64.getEncoder().encodeToString(b)).putLong("pairCodeEpochMs",System.currentTimeMillis()).apply();return b;}
    String getIp(){try{WifiManager wm=(WifiManager)getApplicationContext().getSystemService(WIFI_SERVICE);if(wm!=null&&wm.getConnectionInfo()!=null){String wifi=Formatter.formatIpAddress(wm.getConnectionInfo().getIpAddress());if(isLikelyIp(wifi))return wifi;}}catch(Exception ignored){}try{Enumeration<NetworkInterface> interfaces=NetworkInterface.getNetworkInterfaces();while(interfaces!=null&&interfaces.hasMoreElements()){NetworkInterface ni=interfaces.nextElement();if(ni==null||!ni.isUp()||ni.isLoopback())continue;Enumeration<InetAddress> addresses=ni.getInetAddresses();while(addresses.hasMoreElements()){InetAddress addr=addresses.nextElement();if(addr instanceof Inet4Address&&!addr.isLoopbackAddress()){String ip=addr.getHostAddress();if(isLikelyIp(ip))return ip;}}}}catch(Exception ignored){}return "0.0.0.0";}
    Bitmap qrBitmap(String text,int size){try{BitMatrix m=new MultiFormatWriter().encode(text,BarcodeFormat.QR_CODE,size,size);Bitmap bmp=Bitmap.createBitmap(size,size,Bitmap.Config.RGB_565);for(int x=0;x<size;x++)for(int y=0;y<size;y++)bmp.setPixel(x,y,m.get(x,y)?Color.BLACK:Color.WHITE);return bmp;}catch(Exception e){Bitmap b=Bitmap.createBitmap(10,10,Bitmap.Config.RGB_565);b.eraseColor(Color.LTGRAY);return b;}}
